import { Component, DestroyRef, EventEmitter, inject, Injector, Input, OnDestroy, OnInit, Output } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { NgClass } from '@angular/common';
import { HttpHeaders } from '@angular/common/http';
import { take } from 'rxjs';

/** Pipes */
import { FeedPipe } from '@pipes/feed';
import { ImagePipe } from '@pipes/image';
import { MediaFeedPipe } from '@pipes/media-feed';
import { SanitizePipe } from '@pipes/sanitize';
import { VideoPipe } from '@pipes/video';

/** Interfaces */
import { LPlaylistData } from '@interfaces/local';

/** Services */
import { RequestService } from '@services/request';

/** Environments */
import { API_ENDPOINTS } from '@environments';
import { PROGRAMMATIC } from '@constants';

@Component({
    selector: 'app-content',
    standalone: true,
    imports: [NgClass, FeedPipe, ImagePipe, MediaFeedPipe, SanitizePipe, VideoPipe],
    templateUrl: './content.component.html',
    styleUrls: ['./content.component.scss'],
    providers: [FeedPipe, ImagePipe, MediaFeedPipe, SanitizePipe, VideoPipe],
})
export class ContentComponent implements OnInit, OnDestroy {
    /**
     * The playlist content to be displayed.
     * @type {LPlaylistData}
     */
    @Input() public playlistContent!: LPlaylistData;

    /**
     * Sets the display ticker to on or off
     * @type {boolean}
     * @default true
     */
    @Input() public activateTicker = true;

    /**
     * Event emitter that emits when the display ends.
     * @type {EventEmitter<LPlaylistData>}
     */
    @Output() public displayEnded: EventEmitter<LPlaylistData> = new EventEmitter();

    /**
     * Event emitter that emits a boolean value when there is an error rendering the content.
     * @type {EventEmitter<boolean>}
     */
    @Output() public contentRenderErrored: EventEmitter<LPlaylistData> = new EventEmitter();

    /**
     * Indicates if the content is a feed.
     * @default false
     */
    private isFeed = false;

    /**
     * Indicates if the content is a media feed.
     * @default false
     */
    private isMediaFeed = false;

    /**
     * Indicates if the content is a live stream.
     * @default false
     */
    private isLiveStream = false;

    /**
     * Flag to track if contentEnded has been triggered.
     * @default false
     */
    private contentEndedFlag = false;

    /**
     * Holder for all timeouts of the component
     * @type {Map<string, number>}
     */
    private timeoutMap = new Map<string, ReturnType<typeof setTimeout>>();

    /**
     * Destroy reference for unsubscription
     * @type {DestroyRef}
     */
    protected destroyRef = inject(DestroyRef);

    constructor(
        private _request: RequestService,
        private injector: Injector,
    ) {}

    ngOnInit(): void {
        // Setup Pipes
        const feedPipe = this.injector.get(FeedPipe);
        const mediaFeedPipe = this.injector.get(MediaFeedPipe);
        const { file_type, classification, programmatic_source, file_name, content_id, url } = this.playlistContent;

        // Check file types
        this.isFeed = feedPipe.transform(file_type);
        this.isMediaFeed = this.isFeed && mediaFeedPipe.transform(classification);
        this.isLiveStream = this.isFeed && classification === 'live_stream';

        // Set short duration for live streams
        if (this.isLiveStream) this.playlistContent.duration = 100;

        // Check validity for non-media, non-livestream feeds
        if (this.isFeed && !this.isLiveStream && !this.isMediaFeed) {
            const query = this.playlistContent.url.includes('?')
                ? this.playlistContent.url.substring(this.playlistContent.url.indexOf('?'))
                : '';
            const checkUrl = `${API_ENDPOINTS.local.assets}/${content_id}${query}`;
            this.checkURLValidity(checkUrl);
        }

        // Use cached asset if it meets any of the following conditions:
        const isNonFeedAndNotFromPXChange = !this.isFeed && programmatic_source !== PROGRAMMATIC.pxchange;
        const isMediaFeed = this.isFeed && this.isMediaFeed;
        const isPXChangeWithoutEtag =
            programmatic_source === PROGRAMMATIC.pxchange && !this.playlistContent.url.includes('etag');

        if (isNonFeedAndNotFromPXChange || isMediaFeed || isPXChangeWithoutEtag) {
            const filename = this.isMediaFeed ? this.extractFilenameFromUrl(url) : file_name;
            this.playlistContent.url = `${API_ENDPOINTS.local.assets}/${filename}`;
        }

        this.startTicker();
    }

    ngOnDestroy() {
        // Clear all timeouts when the component is destroyed
        this.timeoutMap.forEach((timeout) => clearTimeout(timeout));
        this.timeoutMap.clear();
    }

    /**
     * Emits an event indicating that there was an error rendering the content.
     * @returns {void}
     */
    public contentErrored(): void {
        if (this.isFeed) return;
        this.contentRenderErrored.emit(this.playlistContent);
    }

    /**
     * Checks the URL validity of the locally downloaded feed
     * If valid, it will use the local version of the feed
     * If not valid it will use the live version of the feed
     *
     * @param url - Local url of the feed
     */
    private async checkURLValidity(url: string): Promise<void> {
        try {
            const response = await fetch(url, { mode: 'no-cors' });
            if (response.ok || response.type === 'opaque') this.playlistContent.url = url;
            else throw new Error(`Local feed fetch failed: ${url}`);
        } catch (error) {
            this.contentErrored();
        }
    }

    /**
     * Starts the ticker to track the display duration of the current playlist content.
     * If the content is an image or feed, sets a timeout to emit the displayEnded event after the duration.
     * @private
     * @returns {void}
     */
    private startTicker(): void {
        const videoPipe = this.injector.get(VideoPipe);

        // Return if playlist content is null or if ticker is not activated (no contents)
        if (!this.playlistContent || !this.activateTicker) return;

        // Ticker for livestream is handled in the playlist component
        if (this.isLiveStream) return;

        /**
         * This is a safety measure for videos that might get stuck.
         * The ticker runs for 1.5 times the duration of the asset, assuming it might still be loading.
         * If the ticker reaches its end, it indicates the asset is stuck and showing a black screen.
         * In this case, the page is reloaded to refresh browser resources.
         */
        if (this.playlistContent.programmatic_source && videoPipe.transform(this.playlistContent.file_type)) {
            this.timeoutMap.set(
                'startTickerVideo',
                setTimeout(
                    () => {
                        // Check if contentEnded has been triggered
                        if (!this.contentEndedFlag) {
                            this.contentEnded();
                        }
                    },
                    this.playlistContent.duration ? this.playlistContent.duration * 1500 : 30000, // Increased by 500 millisecond to give the asset a chance to play
                ),
            );

            return;
        }

        // Ticker for non video dealer assets
        if (!videoPipe.transform(this.playlistContent.file_type)) {
            // Do not run ticket on video asset feeds
            if (this.isMediaFeed && this.playlistContent.classification == 'video_asset') return;

            // Normally run duration ticket for non video contents
            this.timeoutMap.set(
                'startTickerNonVideo',
                setTimeout(
                    () => {
                        if (!this.contentEndedFlag) {
                            // Check if contentEnded has been triggered
                            this.contentEnded();
                        }
                    },
                    this.playlistContent.duration ? this.playlistContent.duration * 1000 : 20000,
                ),
            );
        }
    }

    /**
     * Handles the event when a video ends.
     * Emits the displayEnded event with the current playlist content.
     * @returns {void}
     */
    public contentEnded(): void {
        if (this.contentEndedFlag) return;
        this.contentEndedFlag = true;

        // Clear all timeouts when the component is destroyed
        this.timeoutMap.forEach((timeout) => clearTimeout(timeout));
        this.timeoutMap.clear();

        // Hit play count for the playlist content
        this.hitPlayCount(this.playlistContent.playlist_content_id || this.playlistContent.proof_of_play);
    }

    /**
     * Increases the play count for a playlist content.
     * @param {string} playlistContentId - The ID of the playlist content.
     * @returns {void}
     * @private
     */
    private hitPlayCount(id: string): void {
        const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');

        if (
            this.playlistContent.programmatic_source === PROGRAMMATIC.pxchange ||
            this.playlistContent.programmatic_source === PROGRAMMATIC.vistar
        ) {
            const url = `${API_ENDPOINTS.local.get.programmatic_played}/${id}`;
            this._request.getRequest(url, { headers }).pipe(takeUntilDestroyed(this.destroyRef), take(1)).subscribe();
            return;
        }

        const url = `${API_ENDPOINTS.local.get.log}/${id}`;
        this._request
            .getRequest(url, { headers })
            .pipe(takeUntilDestroyed(this.destroyRef), take(1))
            .subscribe({
                next: () => this.displayEnded.emit(this.playlistContent),
                error: () => this.displayEnded.emit(this.playlistContent),
            });
    }

    /**
     * Extracts filename from asset live URL, used for Media Feed
     * @param url
     * @returns {string}
     */
    private extractFilenameFromUrl(url: string): string {
        const pathname = new URL(url).pathname;
        const segments = pathname.split('/');
        const lastSegment = segments.pop() || '';
        return lastSegment.split(/[?#]/)[0];
    }
}

import { Component, DestroyRef, effect, inject, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { catchError, tap, throwError } from 'rxjs';

/** Components */
import { PlaylistComponent } from '@components/playlist';
import { ZoneComponent } from '@components/zone';

/** Services */
import { RequestService } from '@services/request';

/** Interfaces */
import { LPlayerZone, LPlayerSchedule } from '@interfaces/local';

/** Environments */
import { API_ENDPOINTS } from '@environments';
import { SocketService } from '@services/socket';

@Component({
    selector: 'app-play',
    standalone: true,
    imports: [PlaylistComponent, ZoneComponent],
    templateUrl: './play.component.html',
    styleUrl: './play.component.scss',
})
export class PlayComponent implements OnInit {
    /**
     * Business operation "IS OPEN" indicator
     * @type {boolean}
     * @default true
     */
    public businessOperating = true;

    /**
     * Programmatic flag
     */
    public programmaticEnabled = false;

    /**
     * Holds the player screen and zone properties
     * @default []
     */
    public screenZones: LPlayerZone[] = [];

    /**
     * Indicates the view mode of the content
     * @type {boolean}
     * @default false
     */
    public isFullscreen = false;

    /**
     * Destroy reference for unsubscription
     * @type {DestroyRef}
     */
    protected destroyRef = inject(DestroyRef);

    constructor(
        private _activatedRoute: ActivatedRoute,
        private _router: Router,
        private _request: RequestService,
        private _socket: SocketService,
    ) {
        effect(() => {
            const playerSchedule = this._socket.schedule();
            this.initiatePlayerScheduleChecker(playerSchedule);
        });
    }

    ngOnInit(): void {
        this.initializeLocalStorageValues();
        // this.initializeRouteParams();
        this.initializePlaylistData();
    }

    /**
     * Initializes the local storage values for `businessOperating` and `programmaticEnabled`.
     * Retrieves the last saved values from local storage and parses them as boolean values.
     *
     * @private
     */
    private initializeLocalStorageValues() {
        // Get last saved business operating value in the local storage
        const businessOperatingValue = localStorage.getItem('businessOperating') || '0';
        const businessOperatingParsedValue = parseInt(businessOperatingValue);
        this.businessOperating = businessOperatingParsedValue ? true : false;

        // Get last saved programmatic enabled value in the local storage
        const programmaticEnabledValue = localStorage.getItem('programmaticEnabled') || '0';
        const programmaticEnabledParsedValue = parseInt(programmaticEnabledValue);
        this.programmaticEnabled = programmaticEnabledParsedValue ? true : false;
    }

    /**
     * Initializes the route parameters and updates `businessOperating` and `programmaticEnabled` values.
     * Listens to query parameters from the route and updates component state accordingly.
     *
     * @private
     */
    private initializeRouteParams() {
        this._activatedRoute.queryParamMap.pipe(takeUntilDestroyed(this.destroyRef)).subscribe((data: any) => {
            // Get last saved business operating value in the local storage
            const businessOperatingValue = localStorage.getItem('businessOperating') || '0';

            // Set business operating hours to false if applies
            if (
                data.params.operationHours &&
                data.params.operationHours === 'false' &&
                businessOperatingValue &&
                parseInt(businessOperatingValue) == 0
            ) {
                this.businessOperating = false;
            }

            this.programmaticEnabled = data.params.programmatic
                ? data.params.programmatic === 'true'
                : !!parseInt(localStorage.getItem('programmaticEnabled') || '0');
        });
    }

    /**
     * Initializes playlist data by making API requests to retrieve player screen zones.
     * @returns {void}
     */
    private initializePlaylistData(): void {
        this._request
            .getRequest(API_ENDPOINTS.local.get.template)
            .pipe(
                /** Unsubscribe */
                takeUntilDestroyed(this.destroyRef),

                /** Setup screenzone */
                tap((data: LPlayerZone[]) => {
                    this.screenZones = data;
                }),

                /** Custom error catcher  */
                catchError((error) => {
                    console.error('Error initializing playlist data:', error);
                    this._router.navigate(['screensaver'], { queryParams: { error: 1 } });
                    return throwError(() => ({
                        message: 'Player Server Errored, sending email notification',
                        triggerEmail: true,
                    }));
                }),
            )
            .subscribe();
    }

    /**
     * Initializes socket observable for player schedule
     * @returns {void}
     */
    private initiatePlayerScheduleChecker(data: LPlayerSchedule | null): void {
        if (!data) return;

        this.businessOperating = data.operation_status;
        localStorage.setItem('businessOperating', this.businessOperating ? '1' : '0');
    }

    /**
     * Sets the content display mode
     * @returns {void}
     */
    public setDisplayMode(e: number, zoneOrder: number): void {
        if (this.screenZones.length > 0 && zoneOrder !== 1) return;
        this.isFullscreen = e ? true : false;
    }
}

