// Description: Content Route
// Author(s): Earl Vhin Gabuat (earlgabuat@gmail.com)

import express, { NextFunction, Request, Response } from 'express';
import { error, info, success, warning } from 'log-symbols';
import moment from 'moment';

import { CONTENT_PLAY_LOG, DB_TABLES, DIRECTORY, ERROR_CODES, PLAYLIST_CONTENT_COLUMNS, SOCKET_CLIENT_EVENTS } from '../constants';
import { Assets, License, PlayLogDb } from '../models';
import { ApiService, DownloadService, FileService, PlayLogService, QueryService } from '../services';

const _api = new ApiService();
// Memwatch
// eslint-disable-next-line @typescript-eslint/no-var-requires
const memwatch = require('@airbnb/node-memwatch');

// Declarations
// eslint-disable-next-line @typescript-eslint/no-var-requires
const sqlstring = require('sqlstring-sqlite');
const contentRoutes: express.Router = express.Router();

// Routes
contentRoutes.get('/content', async (req: Request, res: Response, next: NextFunction) => {
	console.log(`====== Downloading Assets ======`);

	// Content Route Timeout
	res.socket?.setTimeout(0);

	try {
		// Required
		const _socket = req.app.get('io');
		const _socket_client = req.app.get('socket_client');

		// Services
		const _query: QueryService = new QueryService();
		const _file: FileService = new FileService();

		// Calls
		const content: Assets[] = await _query.get_all(DB_TABLES.content);
		const license: License[] = await _query.get_all(DB_TABLES.license);
		const assets_server: any = await _file.read_json(`${DIRECTORY.player_server}/package.json`);

		console.log(info, 'Assets Server is', assets_server.error ? 'N/A' : JSON.parse(assets_server).assets_server);

		// Service Required Constructor
		const _download: DownloadService = new DownloadService(_socket, assets_server.error ? null : JSON.parse(assets_server).assets_server);

		console.log(info, 'Taking ownership of /var/www/html/assets');
		await _download.set_assets_folder_ownership();

		console.log(success, `Asset Count: ${content.length}`);

		_socket.emit('download_started', content.length);

		if (content.length > 0) {
			await _download.downloadAssets(content);
			console.log(success, 'All Assets Downloaded');

			// Force Garbage Collection
			memwatch.gc();

			// Player UI will proceed to playing ads at this point.
			_socket_client.emit(SOCKET_CLIENT_EVENTS.content_update_finished, license[0].license_id);

			res.status(200).send({
				assets_dir: assets_server.error ? 'N/A' : JSON.parse(assets_server).assets_server,
				message: 'All Assets Downloaded'
			});
		} else {
			// Force Garbage Collection
			memwatch.gc();
			res.status(200).send({ message: 'No Data Found' });
		}
	} catch (e) {
		const ERROR_MSG = 'contentRoutes__content';
		console.log(error, ERROR_MSG, e);

		res.status(502).json({
			error: {
				message: ERROR_MSG,
				details: 'Failed to download all assets',
				code: ERROR_CODES.DOWNLOAD_ALL_ASSETS_FAIL
			}
		});
	}
});

contentRoutes.get('/content/cleardb', async (req: Request, res: Response, next: NextFunction) => {
	let playLogsSent = false;
	const _playLogs: PlayLogService = new PlayLogService();
	const _query: QueryService = new QueryService();
	console.log('====== Clear Database Started ======');

	const getLicenseData: Promise<License[]> = _query.get_all(DB_TABLES.license);
	const getPlayLogsData: Promise<PlayLogDb[]> = _query.get_all(DB_TABLES.content_play_log);

	try {
		const [license, playLogs] = await Promise.all([getLicenseData, getPlayLogsData]);

		const tablesToDelete = [
			_query.delete_all(DB_TABLES.content).then(() => console.log(success, 'Contents Table Cleared')),
			_query.delete_all(DB_TABLES.playlist_contents).then(() => console.log(success, 'Playlist Contents Table Cleared')),
			_query.delete_all(DB_TABLES.template_zones).then(() => console.log(success, 'Templates Zones Table Cleared')),
			_query.delete_all(DB_TABLES.host_info).then(() => console.log(success, 'Host Info Table Cleared')),
			_query.delete_all(DB_TABLES.computer_usage).then(() => console.log(success, 'Computer Usage Table Cleared')),
			_query.delete_all(DB_TABLES.global_settings).then(() => console.log(success, 'Global Settings Table Cleared')),
			_query.delete_all(DB_TABLES.vistar_content).then(() => console.log(success, 'Vistar Contents Table Cleared')),
			_query.delete_all(DB_TABLES.programmatic_ads).then(() => console.log(success, 'Programmatic Logs Table Cleared'))
		];

		// IF license data and IF play logs exist on the local database THEN send play logs to the server
		if (license.length && playLogs.length) {
			playLogsSent = await _playLogs.sendPlayLogs(playLogs, license[0].license_id);
		}

		// IF play logs were sent successfully THEN add the content_play_log table for clearing
		if (playLogsSent) {
			console.log(success, 'Adding play logs table to be cleared...');
			tablesToDelete.push(_query.delete_all(DB_TABLES.content_play_log).then(() => console.log(success, 'Content Play Logs Table Cleared')));
		} else {
			console.warn(warning, 'Skipping deletion of play logs table.');
		}

		// Clear data from the specified tables
		await Promise.all(tablesToDelete);

		res.status(200).json({ message: 'Database cleared successfully' });
	} catch (err) {
		const ERROR_MSG = 'contentRoutes__cleardb';
		console.error(error, ERROR_MSG, err);

		res.status(500).json({
			error: {
				message: ERROR_MSG,
				details: 'Failed to clear the database',
				code: ERROR_CODES.CLEAR_DB_FAIL
			}
		});
	}
});

contentRoutes.get('/content/clear-data', async (req: Request, res: Response, next: NextFunction) => {
	const _query = new QueryService();
	console.log('====== Clear Content Data Start ======');

	const tablesToDelete = [
		DB_TABLES.content,
		DB_TABLES.playlist_contents,
		DB_TABLES.template_zones,
		DB_TABLES.host_info,
		DB_TABLES.computer_usage,
		DB_TABLES.global_settings,
		DB_TABLES.vistar_content
	];

	const result = await _query.clearTables(tablesToDelete);

	if (!result) {
		const ERROR_MSG = 'contentRoutes__clear_data';

		res.status(200).json({
			message: 'Failed to clear content data!',
			error: ERROR_MSG,
			code: ERROR_CODES.CLEAR_DB_FAIL
		});
	}

	res.status(200).json({ message: 'Success! Content data cleared.' });
});

contentRoutes.get('/content/clear-logs', async (req: Request, res: Response, next: NextFunction) => {
	let response = { message: 'Success! Content play logs cleared.' };
	const _playLog = new PlayLogService();
	const _query = new QueryService();
	console.log('====== Clear Logs Start ======');

	const [license, playLogs] = await Promise.all([_query.getLicenseData(), _query.getPlayLogs()]);

	if (!license || !playLogs) {
		const warningMsg = `No ${!license ? 'license' : 'play logs'} data`;
		console.warn(warning, warningMsg);
		await _query.clearPlayLogTable();
		return res.status(200).json({ message: warningMsg });
	}

	const sentPlayLogs = await _playLog.sendPlayLogs(playLogs, license.license_id);

	if (!sentPlayLogs) {
		response = { message: 'Could not clear logs table.' };
	}

	res.status(200).json(response);
});

contentRoutes.get('/content/reset', async (req: Request, res: Response, next: NextFunction) => {
	let playLogsSent = false;
	const _file: FileService = new FileService();
	const _playLogs: PlayLogService = new PlayLogService();
	const _query: QueryService = new QueryService();
	const _socket_client = req.app.get('socket_client');
	console.log('====== Content Reset Started ======');

	const getLicenseData: Promise<License[]> = _query.get_all(DB_TABLES.license);
	const getPlayLogsData: Promise<PlayLogDb[]> = _query.get_all(DB_TABLES.content_play_log);

	try {
		const [license, playLogs] = await Promise.all([getLicenseData, getPlayLogsData]);

		const tablesToDelete = [
			_query.delete_all(DB_TABLES.content).then(() => console.log(success, 'Contents Table Cleared')),
			_query.delete_all(DB_TABLES.license).then(() => console.log(success, 'License Table Cleared')),
			_query.delete_all(DB_TABLES.playlist_contents).then(() => console.log(success, 'Playlist Contents Table Cleared')),
			_query.delete_all(DB_TABLES.template_zones).then(() => console.log(success, 'Templates Zones Table Cleared')),
			_query.delete_all(DB_TABLES.host_info).then(() => console.log(success, 'Host Info Table Cleared')),
			_query.delete_all(DB_TABLES.apps).then(() => console.log(success, 'Apps Table Cleared')),
			_query.delete_all(DB_TABLES.version).then(() => console.log(success, 'Version Table Cleared')),
			_query.delete_all(DB_TABLES.error_logs).then(() => console.log(success, 'Error Table Cleared')),
			_query.delete_all(DB_TABLES.internet).then(() => console.log(success, 'Internet Table Cleared')),
			_query.delete_all(DB_TABLES.filler_logs).then(() => console.log(success, 'Filler Table Cleared')),
			_query.delete_all(DB_TABLES.update_logs).then(() => console.log(success, 'Update Logs Table Cleared')),
			_query.delete_all(DB_TABLES.computer_usage).then(() => console.log(success, 'Computer Usage Table Cleared')),
			_query.delete_all(DB_TABLES.global_settings).then(() => console.log(success, 'Global Settings Table Cleared')),
			_query.delete_all(DB_TABLES.vistar_content).then(() => console.log(success, 'Vistar Contents Table Cleared')),
			_file.delete_assets().then(() => console.log(success, 'Assets Deleted')),
			_file.delete_screenshots().then(() => console.log(success, 'Screenshots Deleted')),
			_file.delete_config().then(() => console.log(success, 'Config File Deleted'))
		];

		// IF license data and IF play logs exist on the local database THEN send play logs to the server
		if (license.length && playLogs.length) {
			playLogsSent = await _playLogs.sendPlayLogs(playLogs, license[0].license_id);
		}

		// IF play logs were sent successfully
		// THEN add the content_play_log table for clearing
		if (playLogsSent) {
			console.log(success, 'Adding play logs table to be cleared...');
			tablesToDelete.push(_query.delete_all(DB_TABLES.content_play_log).then(() => console.log(success, 'Content Play Logs Table Cleared')));
		} else {
			console.warn(warning, 'Skipping deletion of play logs table.');
		}

		// Clear data from the specified tables
		await Promise.all(tablesToDelete);

		// Renew Socket Server Connection ID
		_socket_client.disconnect();
		_socket_client.connect();

		res.status(200).json({ message: 'Player Data Cleared' });
	} catch (err) {
		const ERROR_MSG = 'contentRoutes__reset';
		console.error(error, ERROR_MSG, err);

		res.status(500).json({
			error: {
				message: ERROR_MSG,
				details: 'Failed to reset contents',
				code: ERROR_CODES.RESET_CONTENT_FAIL
			}
		});
	}
});

