import { Component, DestroyRef, effect, inject, OnInit } from '@angular/core';
import { NgClass } from '@angular/common';
import { HttpHeaders } from '@angular/common/http';
import { ActivatedRoute, Router } from '@angular/router';
import { catchError, lastValueFrom, Observable, of, Subject, switchMap, tap } from 'rxjs';

/** Components */
import { AnimatedLoaderComponent } from '@components/animated-loader';
import { ProgressBarComponent } from '@components/progress-bar';

/** Interfaces */
import { AssetDownloadProgress, ProgressStep } from '@interfaces/misc';
import { Content, PlayerData } from '@interfaces/cloud';

/** Constants */
import { CONTENT_DOWNLOAD_STEPS, SERVER_ERROR_CODE } from '@constants';

/** Services */
import { RequestService } from '@services/request';
import { SocketService } from '@services/socket';

/** Environments */
import { API_ENDPOINTS } from '@environments';
import { LError, LLicenseSettings, LPlayerSchedule } from '@interfaces/local';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({
    selector: 'app-content-setup',
    standalone: true,
    imports: [NgClass, AnimatedLoaderComponent, ProgressBarComponent],
    templateUrl: './content-setup.component.html',
    styleUrl: './content-setup.component.scss',
})
export class ContentSetupComponent implements OnInit {
    /**
     * The progress of asset downloads.
     * @default new Subject<{ key: string; value: number }>()
     */
    public assetDownloadProgress: Subject<{ key: string; value: number }> = new Subject<{
        key: string;
        value: number;
    }>();

    /**
     * The current progress value.
     * @default 0
     */
    public currentProgress = 0;

    /**
     * The list of downloaded player assets.
     * @default []
     */
    public downloadedPlayerAssets: string[] = [];

    /**
     * Indicates if the download is completed.
     * @default false
     */
    public downloadCompleted = false;

    /**
     * The license ID.
     * @default ''
     */
    public licenseId = '';

    /**
     * The license key.
     * @default ''
     */
    public licenseKey = '';

    /**
     * The player assets to be downloaded.
     * @type {Content[]}
     * @default []
     */
    public playerAssets: Content[] = [];

    /**
     * Programmatic flag
     * @default true
     */
    private programmaticEnabled = true;

    /**
     * The width of the progress indicator.
     * @default 50
     */
    public progressWidth = 50;

    /**
     * The total width of the progress indicator.
     * @default 50
     */
    public progressWidthTotal = 50;

    /**
     * Indicates if the system is ready to download.
     * @default false
     */
    public readyToDownload = false;

    /**
     * Indicates if a refetch is needed.
     * @default false
     */
    public refetch = false;

    /**
     * The number of steps in the process.
     * @default 4
     */
    public stepCount = 5;

    /**
     * The subtitle displayed during the process.
     * @default 'Please Wait . . .'
     */
    public subtitle = 'Please Wait . . .';

    /**
     * The title displayed during the process.
     * @default 'Getting Player Data'
     */
    public title = 'Getting Player Data';

    /**
     * Player offline status
     * @default false;
     */
    private isOffline = false;

    /**
     * The steps for content download.
     * @default CONTENT_DOWNLOAD_STEPS
     * @private
     */
    private steps = CONTENT_DOWNLOAD_STEPS;

    /**
     * Holder for all timeouts of the component
     * @type {Map<string, number>}
     */
    private timeoutMap = new Map<string, ReturnType<typeof setTimeout>>();

    /**
     * Destroy reference for unsubscription
     * @type {DestroyRef}
     */
    protected destroyRef = inject(DestroyRef);

    constructor(
        private _request: RequestService,
        private _activatedRoute: ActivatedRoute,
        private _socket: SocketService,
        private _router: Router,
    ) {
        this._socket.downloaded.set(null);

        effect(() => {
            const downloaded = this._socket.downloaded();
            this.assetDownloadWatch(downloaded);
        });
    }

    ngOnInit(): void {
        this._activatedRoute.queryParamMap.pipe(takeUntilDestroyed(this.destroyRef)).subscribe((data: any) => {
            this.licenseKey = data.params.licenseKey;
            this.licenseId = data.params.licenseId;
            this.refetch = data.params.refetch === 'true';
            this.isOffline = data.params.offline === 'true';
        });

        this.pingLocalServer();
    }

    ngOnDestroy() {
        // Clear all timeouts when the component is destroyed
        this.timeoutMap.forEach((timeout) => clearTimeout(timeout));
        this.timeoutMap.clear();
    }

    /**
     * Watches for asset download progress and updates the progress state accordingly.
     * Moves completed downloads to the beginning of the assets list and adds them to the downloaded list.
     * @private
     * @returns {void}
     */
    private assetDownloadWatch(data: AssetDownloadProgress | null): void {
        if (!data) return;

        if (!this.playerAssets.find((asset) => asset.contentId === data.content_id)) return;

        this.playerAssets.find((asset) => asset.contentId === data.content_id)!.progressWidthTracker = Number(
            data.progress || 0,
        );

        this.timeoutMap.set(
            'assetDownloadWatch',
            setTimeout(() => {
                if (Number(data.progress) === 100) {
                    /** Find the index of the content object */
                    const index = this.playerAssets.findIndex((asset) => asset.contentId === data.content_id);

                    /** If found, remove the object and unshift it to the beginning of the array */
                    if (index !== -1) {
                        const [contentObject] = this.playerAssets.splice(index, 1);
                        this.playerAssets.unshift(contentObject);
                    }

                    this.downloadedPlayerAssets.push(data.content_id);
                }
            }, 700),
        );
    }

    /**
     * Retrieves player data, clears the database, saves player data locally,
     * and starts the asset download watcher. Updates the title and subtitle
     * throughout the process and navigates to the play route upon completion.
     * @private
     * @returns {void}
     */
    private getPlayerData(): void {
        /**
         * Conditional Process
         * Skipping some processes if isOffline value is true
         */
        const process$: Observable<any> = this.isOffline ? this.getLocalPlayerData() : this.getLivePlayerData();
        let getScheduleUrl = API_ENDPOINTS.local.get.schedule;
        if (this.isOffline) getScheduleUrl += '?isOffline=true';

        process$
            .pipe(
                /** Unsubscribe */
                takeUntilDestroyed(this.destroyRef),

                /** Get Host Schedule */
                tap(() => {
                    const titleSubtitle = this.getSubtitleMessage(5);
                    this.title = titleSubtitle.title;
                    this.subtitle = titleSubtitle.subtitle;
                    this.readyToDownload = false;
                }),
                switchMap(() => this._request.getRequest(getScheduleUrl)),
            )
            .subscribe({
                next: (data: LPlayerSchedule | any) => {
                    this.title = data.operation_status ? 'Host is Open' : 'Host is Closed';
                    const opening = data.opening_hour;
                    const closing = data.closing_hour;

                    // If either one of the hours are null then set the subtitle to blank instead of showing null
                    const scheduleText = !opening || !closing ? '' : `${opening} - ${closing}`;
                    this.subtitle = scheduleText;
                    this.downloadCompleted = true;

                    // Set localstorage values
                    localStorage.setItem('programmaticEnabled', this.programmaticEnabled ? '1' : '0');
                    localStorage.setItem('businessOperating', data.operation_status ? '1' : '0');

                    // Reset schedule signal
                    this._socket.schedule.set(null);

                    this.timeoutMap.set(
                        'getPlayerData',
                        setTimeout(() => {
                            this._router.navigate(['play'], {
                                queryParams: {
                                    operationHours: data.operation_status,
                                    programmatic: this.programmaticEnabled,
                                },
                            });
                        }, 5000),
                    );
                },
                error: (error: LError) => {
                    /** Handle any errors that occur during the observable chain */
                    console.error('An error occurred ===>', { error });

                    /** @todo - improve error object returned by the API */
                    if (error && error.error && error.error.error) {
                        const { code } = error.error.error;

                        if (code === SERVER_ERROR_CODE.no_license) {
                            this._router.navigate(['license-setup']);
                            return;
                        }

                        // Handle specific error codes
                        if (code === SERVER_ERROR_CODE.player_data_failed_save) {
                            this._router.navigate(['screensaver']);
                            return;
                        }
                    }

                    /** Update the title to reflect the error state */
                    this.title = 'Error Occurred';
                    this.subtitle = 'Something went wrong, please contact your administrator';

                    /** Redirect to offline mode */
                    this.timeoutMap.set(
                        'getPlayerDataErrored',
                        setTimeout(() => {
                            this._router.navigateByUrl('/', { skipLocationChange: true }).then(() => {
                                this._router.navigate(['content-setup'], { queryParams: { offline: 'true' } });
                            });
                        }, 2000),
                    );
                },
            });
    }

    /**
     * Checks the local player server availability and continues the process
     * If the player server errored, it redirects to the screensaver page
     *
     * @returns {Observable<any>}
     */
    private pingLocalServer(): void {
        const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');
        this._request
            .getRequest(API_ENDPOINTS.local.get.ping, { headers })
            .pipe(takeUntilDestroyed(this.destroyRef))
            .subscribe({
                next: () => {
                    if (this.refetch) {
                        this.initiateRefetch();
                        return;
                    }

                    this.getPlayerData();
                },
                error: (e: { error: { error: { message: string; code: string } } }) => {
                    // Checks if the player server is able to produce a custom error, means its up
                    if (e.error && e.error?.error?.code.length) {
                        this.getPlayerData();
                        return;
                    }

                    this._router.navigate(['screensaver'], {
                        queryParams: { error: SERVER_ERROR_CODE.player_server_error },
                    });
                },
            });
    }

    /**
     * Get local player data. This runs when the player is offline
     * @returns {Observable<any>}
     */
    private getLocalPlayerData(): Observable<any> {
        const headers = new HttpHeaders().set('Custom-Error-Code', SERVER_ERROR_CODE.local_player_data_error);
        return this._request.getRequest(API_ENDPOINTS.local.get.check_license, { headers }).pipe(
            /** Unsubscribe */
            takeUntilDestroyed(this.destroyRef),

            /** Get player information */
            tap((availablePlayerLicense: any[]) => {
                this.title = 'Getting Local Data';
                this.subtitle = 'Player is offline, will use last saved data if present';

                /** Getting locally saved license */
                const licenseData: LLicenseSettings = availablePlayerLicense[0];
                localStorage.setItem('licenseData', JSON.stringify(licenseData));
            }),
            switchMap(async () => {
                /** Getting locally saved player data */
                const playerData: PlayerData = await lastValueFrom(
                    this._request.getRequest(`${API_ENDPOINTS.local.api}/player-data.json`, { headers }, true),
                );

                /** If no player data fetched */
                if (!playerData) return;

                /** If player data is available, setup the following backups */
                localStorage.setItem('playerData', JSON.stringify(playerData));
                localStorage.setItem('screenType', playerData.piContents.screenType.name);
            }),
        );
    }

    /**
     * Get live player data. This will run if player is online
     * @returns {Observable<any>}
     */
    private getLivePlayerData(): Observable<any> {
        const localStorageItems = Object.keys({ ...localStorage });

        if (localStorageItems.length) {
            localStorageItems.forEach((localStorageKey: string) => {
                if (localStorageKey === 'licenseData') return;
                localStorage.removeItem(localStorageKey);
            });
        }

        return this._request.getRequest(API_ENDPOINTS.local.get.ping).pipe(
            /** Unsubscribe */
            takeUntilDestroyed(this.destroyRef),

            /** Get Player Data */
            tap(() => {
                const titleSubtitle = this.getSubtitleMessage(1);
                this.title = titleSubtitle.title;
                this.subtitle = titleSubtitle.subtitle;
            }),
            switchMap(() => this._request.getRequest(`${API_ENDPOINTS.local.get.player_data}${this.licenseKey}`)),
            tap(() => {
                const titleSubtitle = this.getSubtitleMessage(2);
                this.title = titleSubtitle.title;
                this.subtitle = titleSubtitle.subtitle;
            }),
            switchMap(async (playerData: PlayerData) => {
                /** Setting up a global variable for player assets */
                this.playerAssets = playerData.piContents?.contents || [];

                /** Save player data and screen type to local storage for quick access */
                localStorage.setItem('playerData', JSON.stringify(playerData));
                localStorage.setItem('screenType', playerData.piContents.screenType.name);

                /** Now clear the database after data is ready */
                await lastValueFrom(this._request.getRequest(API_ENDPOINTS.local.get.cleardb));

                /** Return Player Data */
                return await lastValueFrom(
                    this._request.postRequest(`${API_ENDPOINTS.local.post.save_player_data}`, playerData),
                );
            }),
            /** Downloading Media Files */
            tap(() => {
                const titleSubtitle = this.getSubtitleMessage(3);
                this.title = titleSubtitle.title;
                this.subtitle = titleSubtitle.subtitle;
                this.readyToDownload = true;
            }),
            switchMap(() => this._request.getRequest(API_ENDPOINTS.local.get.download_assets)),
            /** Setup Programmatic */
            tap(() => {
                const titleSubtitle = this.getSubtitleMessage(4);
                this.title = titleSubtitle.title;
                this.subtitle = titleSubtitle.subtitle;
                this.readyToDownload = true;
            }),
            switchMap(() => {
                const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');
                return this._request.getRequest(API_ENDPOINTS.local.get.programmatic_adrequest, { headers }).pipe(
                    tap((response: { data: { programmatic: boolean } }) => {
                        if (response.data && response.data.programmatic !== undefined) {
                            this.programmaticEnabled = response.data.programmatic;
                            localStorage.setItem('programmaticEnabled', this.programmaticEnabled ? '1' : '0');
                        }
                    }),
                    catchError((error) => {
                        console.error('Programmatic ad request failed:', error);

                        // Setting programmaticDisabled to false in case of error
                        this.programmaticEnabled = false;

                        // Return an empty observable to continue the chain
                        return of(null);
                    }),
                );
            }),
        );
    }

    /**
     * Retrieves the subtitle message based on the current step. Optionally increases
     * the progress width.
     * @private
     * @param {number} step - The current step in the process.
     * @param {boolean} [increaseProgress=true] - Whether to increase the progress width.
     * @returns {ProgressStep} The title, subtitle and step for the given step.
     */
    private getSubtitleMessage(step: number, increaseProgress = true): ProgressStep {
        if (increaseProgress) {
            this.progressWidth = 50;
            this.currentProgress++;
            this.progressWidth += (this.currentProgress / this.stepCount) * this.progressWidthTotal;
        }

        return this.steps.find((s) => s.step === step) || { title: '', subtitle: '', step: 0 };
    }

    /**
     * Initiates a refetch operation by making a GET request to
     * the specified endpoint, then goes through the player data fetch.
     * @private
     */
    private initiateRefetch(): void {
        const titleSubtitle = this.getSubtitleMessage(5);
        this.title = titleSubtitle.title;
        this.subtitle = titleSubtitle.subtitle;
        this._request
            .getRequest(API_ENDPOINTS.local.get.refetch)
            .pipe(takeUntilDestroyed(this.destroyRef))
            .subscribe({
                next: () => this.getPlayerData(),
                error: (error) => {
                    /** Handle any errors that occur during the observable chain */
                    console.error('An error occurred:', error);

                    /** Update the title to reflect the error state */
                    this.title = 'Error Occurred';
                    this.subtitle = 'Something went wrong, please contact your administrator';
                },
            });
    }

    /** NgFor tracker
     * @public
     * @returns number
     */
    public trackByAsset(index: number, asset: Content): string {
        return asset.playlistContentId;
    }
}

import { Component, DestroyRef, EventEmitter, inject, Input, OnDestroy, OnInit, Output } from '@angular/core';
import { HttpHeaders } from '@angular/common/http';
import { take } from 'rxjs';

/** Components */
import { ContentComponent } from '@components/content';

/** Services */
import { HelperService } from '@services/helper';
import { RequestService } from '@services/request';
import { SocketService } from '@services/socket';

/** Environments */
import { API_ENDPOINTS } from '@environments';

/** Interfaces */
import { LPlaylistData, LProgrammaticAd, LProgrammaticAdsResponse } from '@interfaces/local';

/** Constants */
import { PLAY_TYPE } from '@constants';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({
    selector: 'app-playlist',
    standalone: true,
    imports: [ContentComponent],
    templateUrl: './playlist.component.html',
    styleUrl: './playlist.component.scss',
})
export class PlaylistComponent implements OnInit, OnDestroy {
    /**
     * Indicates that the zone holding this playlist is a main zone
     */
    @Input() public isMainzone = false;

    /**
     * Playlist ID to be used to fetch playlist data.
     * @type {string}
     * @default ''
     */
    @Input() public playlistId: string = '';

    /**
     * Programmatic ads to be diplayed
     * @type {LProgrammaticAds[]}
     * @default []
     */
    @Input() public programmaticAds: LProgrammaticAd[] = [];

    /**
     * Programmatic enabled flag
     * @type {boolean}
     * @default true
     */
    @Input() public programmaticEnabled: boolean = false;

    /**
     * Emits the playlist content is_fullscreen value
     * @type {number}
     * @default ''
     */
    @Output() public onDisplayModeChecked: EventEmitter<number> = new EventEmitter();

    /**
     * The current playlist content item.
     * @type {PlaylistData | null}
     * @default null
     */
    public currentPlaylistContent: LPlaylistData | null = null;

    /**
     * The current livestream ad.
     * @type {PlaylistData | null}
     * @default null
     */
    public currentLivestreamAd: LPlaylistData | null = null;

    /**
     * The current playlist sequence
     * @type {number}
     * @default 0
     */
    public currentSequence: number = 0;

    /**
     * The current vendor content sequence tracker but starts with 1
     * @type {number}
     * @default 1
     */
    public currentVendorSequence: number = 1;

    /**
     * Array of playlist items were not downloaded
     * @type {LPlaylistData[]}
     */
    private failedDownloads: LPlaylistData[] = [];

    /**
     * Array of playlist items that are classified as livestream
     * @type {LPlaylistData[]}
     * @default []
     */
    private livestreamAd: LPlaylistData[] = [];

    /**
     * Indicates if the number of playable content the playlist has
     * @type {number}
     * @default 0
     */
    public playableContentCount: number = 0;

    /**
     * Final flag for displaying contents. This is only set to true once all of the playlist data processing
     * is finished
     *
     * @type {boolean}
     * @default false
     */
    public isPlaylistDataReady: boolean = false;

    /**
     * Indicates if the playlist has only one content
     * @type {boolean}
     * @default false
     */
    public isSingleContent: boolean = false;

    /**
     * Array of playlist items.
     * @type {LPlaylistData[]}
     * @default []
     */
    private playlist: LPlaylistData[] = [];

    /**
     * Holds the screen type essential for programmatic feature
     * @type {string}
     * @default '';
     */
    private screenType: string = '';

    /**
     * Set the ticker's activate status
     * @type {boolean}
     * @default true
     */
    public tickerActivated: boolean = true;

    /**
     * Timeout reference
     * @type {number}
     */
    private timeoutRef: number = 0;

    /**
     * Holder for all timeouts of the component
     * @type {Map<string, number>}
     */
    private timeoutMap = new Map<string, ReturnType<typeof setTimeout>>();

    /**
     * Array of vendor ads mapped into playlist data.
     * @type {LPlaylistData[]}
     * @default []
     */
    private vendorAds: LPlaylistData[] = [];

    /**
     * Destroy reference for unsubscription
     * @type {DestroyRef}
     */
    protected destroyRef = inject(DestroyRef);

    /**
     * The sequence assigned for the vendor ad
     * @type {number}
     * @default 4 - means programmatic ads will play at every after 4th sequence in the playlist
     * See sample below:
     * p - playlist
     * v - vendor
     * p p p p v p p p p v p p p p v
     * p p p p v p p p p v p p p p v
     */
    private vendorAdPlayPosition: number = 6;

    constructor(
        private _helper: HelperService,
        private _request: RequestService,
        private _socket: SocketService,
    ) {
        this.screenType = localStorage.getItem('screenType') || '';
    }

    ngOnInit(): void {
        this.getPlaylistData();
    }

    ngOnDestroy() {
        clearTimeout(this.timeoutRef);

        // Clear all timeouts when the component is destroyed
        this.timeoutMap.forEach((timeout) => clearTimeout(timeout));
        this.timeoutMap.clear();
    }

    /**
     * Fetches playlist data using the current playlist ID.
     * If the playlist ID is not set, the method returns early.
     * @private
     * @returns {void}
     */
    private getPlaylistData(update: boolean = false): void {
        if (!this.playlistId) return;

        this._request
            .getRequest(`${API_ENDPOINTS.local.get.playlist}${this.playlistId}`)
            .pipe(takeUntilDestroyed(this.destroyRef))
            .subscribe({
                next: (playlist: LPlaylistData[]) => {
                    // Sort the playlist by sequence
                    this.playlist = playlist.sort((a, b) => a.sequence - b.sequence);

                    // Failed Downloads
                    this.failedDownloads = [...this.playlist.filter((p) => p.downloaded == 0)];

                    // Remove failed downloads
                    this.playlist = [...this.playlist.filter((p) => p.downloaded !== 0)];

                    // Just updating the playlist content, no need to run anything else
                    if (update) return;

                    // Set play triggers
                    this.checkPlayables();

                    // If there are no playable contents then do not proceed
                    if (!this.playableContentCount) return;

                    // Run programmatic call
                    if (this.isMainzone) this.getProgrammaticAds();

                    // Store Livestreams and run the ticker if any livestreams exist
                    this.livestreamAd = this.playlist.filter((p) => p.classification === 'live_stream');
                    if (this.livestreamAd.length) this.livestreamTicker();

                    // Start playing the ad if not in update mode
                    this.playAd();

                    // Mark the playlist as ready
                    this.isPlaylistDataReady = true;
                },

                error: (err) => console.error({ err }),
            });
    }

    private retryFailedDownloads() {
        const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');
        this._request
            .getRequest(`${API_ENDPOINTS.local.get.download_assets}?retry=1`, { headers })
            .pipe(takeUntilDestroyed(this.destroyRef))
            .subscribe({
                next: () => this.getPlaylistData(true),
                error: () => console.log('Retry Attempt: Failed to download assets'),
            });
    }

    /**
     * Checks and manages the display of livestream ads at regular intervals.
     *
     * @private
     * @returns {void}
     */
    private livestreamTicker(): void {
        if (!this.livestreamAd.length) return;

        this.timeoutMap.set(
            'livestreamTicker',
            setTimeout(() => {
                const livestreamAd = this.livestreamAd.find((ad) => this._helper.canPlayContent(ad));

                /** No livestream ad available to play */
                if (!livestreamAd) {
                    /**
                     * No livestream ad available to play, but if the current playlist content
                     * playing is a livestream, then we need to stop it
                     */
                    if (this.currentPlaylistContent && this.currentPlaylistContent.classification === 'live_stream') {
                        /** Reset the current playlist content value */
                        this.currentPlaylistContent = null;

                        /** Totally remove the livestream */
                        this.livestreamAd = this.livestreamAd.filter(
                            (ad) => ad.playlist_content_id !== this.currentLivestreamAd?.playlist_content_id,
                        );

                        /** Play ads normally */
                        this.timeoutRef = setTimeout(() => {
                            this.playAd();
                        }, 0);
                    }

                    this.livestreamTicker();
                    return;
                }

                /** If current playlist content is playing a normal ad, switch it to livestream ad if its time to play */
                if (this.currentPlaylistContent?.classification !== 'live_stream') this.currentPlaylistContent = null;

                /** Set the currently playing content's value to livestream */
                this.timeoutRef = setTimeout(() => {
                    this.currentPlaylistContent = livestreamAd;
                    this.currentLivestreamAd = livestreamAd;
                    this.onDisplayModeChecked.emit(this.currentLivestreamAd.is_fullscreen);
                }, 0);

                this.livestreamTicker();
            }, 5000),
        );
    }

    /**
     * Fetches and processes programmatic ads if enabled.
     *
     * @private
     * @returns {void}
     */
    private getProgrammaticAds(): void {
        if (!this.programmaticEnabled || this.screenType !== 'ad' || !this.playableContentCount) return;

        const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');
        this._request
            .getRequest(API_ENDPOINTS.local.get.programmatic_ads, { headers })
            .pipe(takeUntilDestroyed(this.destroyRef))
            .subscribe({
                next: (ads: LProgrammaticAdsResponse) => {
                    this.vendorAds = [
                        ...ads.data.map((ad, index) => ({
                            playlist_id: null,
                            playlist_content_id: null,
                            programmatic_ad_id: ad.id,
                            programmatic_source: ad.creative_source,
                            content_id: ad.id,
                            file_name: ad.creative_name,
                            url: ad.creative_url,
                            file_type: ad.creative_type,
                            handler_id: null,
                            sequence: index,
                            is_fullscreen: 1,
                            duration: ad.duration,
                            title: ad.creative_name,
                            play_type: PLAY_TYPE.default,
                            alternate_week: null,
                            date_from: null,
                            date_to: null,
                            play_days: null,
                            play_time_start: null,
                            play_time_end: null,
                            proof_of_play: ad.proof_of_play,
                            credits: null,
                            credit_count: null,
                            schedule_status: null,
                            schedule_status_sent: null,
                            classification: null,
                            played: ad.played,
                        })),
                    ];

                    if (
                        this.playableContentCount > 1 &&
                        this.playlist.length < this.vendorAdPlayPosition &&
                        this.isMainzone
                    ) {
                        this.playlist = [...this.playlist, ...this.vendorAds];
                    }
                },
            });
    }

    /**
     * Handles the event when there is an error rendering the content.
     * Increments the current sequence, sets the current playlist content to null,
     * and calls the playAd method to play the next advertisement after a brief delay.
     * @todo - skipping the content but let's improve error handling here soon, maybe a logging mechanism that will inform dealer about the errored asset
     * @public
     * @returns {void}
     */
    public onContentRenderError(e: any): void {
        if (this.playlist.length <= 1) return;
        this.currentSequence += 1;

        if (this.playlist[this.currentSequence] && !this.playlist[this.currentSequence].programmatic_source)
            this.currentVendorSequence += 1;
        this.currentPlaylistContent = null;

        this.timeoutMap.set(
            'onContentRenderError',
            setTimeout(() => {
                this.saveCurrentPlaylistSequence(this.currentSequence);
                this.playAd();
            }, 0),
        );
    }

    /**
     * Handles the event when the display ends. Increments the current
     * sequence and calls the playAd method to play the next advertisement.
     * @public
     * @returns {void}
     */
    public onDisplayEnded(): void {
        if (this.playableContentCount > 1 || this.playlist.length > 1) {
            if (!this.currentPlaylistContent?.programmatic_source) {
                this.currentVendorSequence += 1;
            }

            this.currentPlaylistContent = null;
        } else {
            // Single Content: Reset the current playlist content and set sequence to 0
            this.currentPlaylistContent = null;
            this.currentSequence = 0;
        }

        this.currentSequence += 1;

        this.timeoutMap.set(
            'onDisplayEnded',
            setTimeout(() => {
                this.saveCurrentPlaylistSequence(this.currentSequence);
                this.playAd();
            }, 0),
        );
    }

    /**
     * Plays the advertisement by setting the current playlist content
     * based on the current sequence. If the current sequence exceeds
     * the length of the playlist, it resets the sequence to 0.
     * @private
     * @returns {void}
     */
    private playAd(): void {
        // Set the current sequence if there is cached value else use the current value
        this.currentSequence = parseInt(localStorage.getItem(this.playlistId) || this.currentSequence.toString());

        // Do not proceed if playlist has no contents
        if (this.playlist.length === 0) {
            console.warn('Playlist is empty!');
            return;
        }

        if (
            this.isMainzone &&
            this.currentVendorSequence - 1 !== 0 &&
            (this.currentVendorSequence - 1) % this.vendorAdPlayPosition === 0
        ) {
            if (this.vendorAds.length) {
                const vendorAd = this.vendorAds[0];
                this.currentPlaylistContent = vendorAd;
                this.onDisplayModeChecked.emit(vendorAd.is_fullscreen);
                this.currentSequence = this.currentSequence - 1;
                this.currentVendorSequence = 1;

                /** Send programmatic screenshot */
                this.timeoutMap.set(
                    'playAd',
                    setTimeout(() => {
                        this.triggerProgrammaticPlaying(vendorAd);
                    }, 5000),
                );

                /** Trigger currently playing signal */
                this._socket.currentPlayingContent.set({
                    playlistContentId: this.currentPlaylistContent.playlist_content_id,
                    programmatic: this.currentPlaylistContent.programmatic_source,
                });

                return;
            }

            /** Retry adrequest */
            if (this.programmaticEnabled) this.triggerProgrammaticAdRequest();
        }

        do {
            // Do not proceed if there is no content data
            if (!this.playlist[this.currentSequence]) break;

            if (this._helper.canPlayContent(this.playlist[this.currentSequence])) {
                this.currentPlaylistContent = this.playlist[this.currentSequence];
                this.onDisplayModeChecked.emit(this.currentPlaylistContent.is_fullscreen);

                /** Trigger programmatic ad screenshot */
                if (this.isMainzone && this.playlist[this.currentSequence].programmatic_source) {
                    this.timeoutMap.set(
                        'programmaticAdScreenshot',
                        setTimeout(() => {
                            this.triggerProgrammaticPlaying(this.playlist[this.currentSequence]);
                        }, 5000),
                    );
                }

                /** Trigger currently playing signal */
                this._socket.currentPlayingContent.set({
                    playlistContentId: this.currentPlaylistContent?.playlist_content_id || '',
                    programmatic: this.currentPlaylistContent.programmatic_source,
                });

                return;
            }

            this.currentSequence += 1;
            this.saveCurrentPlaylistSequence(this.currentSequence);
        } while (this.currentSequence < this.playlist.length);

        // Reset the current sequence once it reaches the end of the playlist
        if (this.currentSequence >= this.playlist.length) this.currentSequence = 0;

        this.saveCurrentPlaylistSequence(this.currentSequence);

        // Retry failed downloads
        if (this.failedDownloads.length) this.retryFailedDownloads();

        this.playAd();
    }

    /**
     * Checks the playable contents in the playlist and updates the ticker activation status.
     *
     * - Sets `playableContentCount` to the number of playable contents in the playlist.
     * - Activates or deactivates the ticker based on the playable content count and playlist length.
     * - If the playable content count is 1 or less and there are multiple items in the playlist, rechecks after 20 seconds.
     *
     * @private
     * @returns {void}
     */
    private checkPlayables(): void {
        // Set hasPlayable flag
        this.playableContentCount = this.playlist.filter((p) => this._helper.canPlayContent(p)).length;

        // If there are no playable contents or if there is only one content, disable the ticker
        this.tickerActivated = this.playableContentCount > 0 && this.playlist.length > 1;

        // Recheck for playables
        if (this.playableContentCount <= 1 && this.playlist.length > 1) {
            this.timeoutMap.set(
                'checkPlayables',
                setTimeout(() => this.checkPlayables(), 20000),
            );
        }
    }

    /**
     * Reloads the page while retaining URL params
     * This will clear all browser cache and free up resources
     */
    private reloadPage() {
        if (this.isMainzone) {
            const params = window.location.search; // Get the query parameters
            const url = window.location.pathname + params; // Construct the full URL
            window.location.replace(url); // Reload the page with the full URL
            return;
        }
    }

    /**
     * Saves the current playlist sequence that will
     * allow the player to look up in an event of a page reload
     * making sure the sequence continues
     * @param currentPlaylistSequence
     */
    private saveCurrentPlaylistSequence(currentPlaylistSequence: number): void {
        localStorage.setItem(this.playlistId, currentPlaylistSequence.toString());
    }

    /**
     * Trigger programmatic playing request,
     * This sends a screenshot as a proof of play
     */
    private triggerProgrammaticPlaying(playlistContent: LPlaylistData): void {
        const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');
        this._request
            .getRequest(`${API_ENDPOINTS.local.get.programmatic_playing}/${playlistContent.proof_of_play}`, { headers })
            .pipe(takeUntilDestroyed(this.destroyRef), take(1))
            .subscribe({
                next: () => {
                    if (this.programmaticEnabled) this.triggerProgrammaticAdRequest();
                },
            });
    }

    /**
     * Trigger ad request from programmatic vendors
     * to renew and download programmatic ads data
     */
    private triggerProgrammaticAdRequest(): void {
        const headers = new HttpHeaders().set('Exclude-Interceptor', 'true');
        this._request
            .getRequest(API_ENDPOINTS.local.get.programmatic_adrequest, { headers })
            .pipe(takeUntilDestroyed(this.destroyRef), take(1))
            .subscribe({
                next: () => this.getProgrammaticAds(),
                error: () => {
                    this.programmaticEnabled = false;
                },
            });
    }
}

