// Description: Template Route
// Author(s): Earl Vhin Gabuat (earlgabuat@gmail.com)

import axios from 'axios';
import express, { NextFunction, Request, Response } from 'express';
import { error, success } from 'log-symbols';

import { DB_TABLES, PLAYLIST_CONTENT_COLUMNS } from '../constants/DatabaseTables';
import { environment } from '../environment/environment';
import { QueryService } from '../services/QueryService';

// Declarations
const playlistRoutes: express.Router = express.Router();
const sqlstring = require('sqlstring-sqlite');

// Routes
playlistRoutes.post('/playlist/updateContentStatus', async (req: Request, res: Response, next: NextFunction) => {
	const _query = new QueryService();
	const { api_base_url, post } = environment;
	const { playlist_content_status } = post;
	const endpoint = `${api_base_url}${playlist_content_status}`;

	try {
		const playlistContentId = sqlstring.escape(req.body.playlistContentId);
		const playlistContent = await _query.get_by_data(DB_TABLES.playlist_contents, PLAYLIST_CONTENT_COLUMNS.playlist_content_id, playlistContentId);

		await _query.update_data(
			DB_TABLES.playlist_contents,
			[`${PLAYLIST_CONTENT_COLUMNS.schedule_status}=-1`],
			PLAYLIST_CONTENT_COLUMNS.playlist_content_id,
			sqlstring.escape(req.body.playlistContentId)
		);

		await axios.post(endpoint, {
			playlistContentId: req.body.playlistContentId,
			status: 'I'
		});

		if (playlistContent[0].schedule_status_sent !== 1) {
			await _query.update_data(
				DB_TABLES.playlist_contents,
				[`${PLAYLIST_CONTENT_COLUMNS.schedule_status_sent}=1`],
				PLAYLIST_CONTENT_COLUMNS.playlist_content_id,
