// Description: Player Route
// Author(s): Earl Vhin Gabuat (earlgabuat@gmail.com)

import { AxiosResponse } from 'axios';
import express, { NextFunction, Request, Response } from 'express';
import { error, info, success, warning } from 'log-symbols';
import * as os from 'os';
import path from 'path';
import * as fs from 'fs-extra';

import {
	CONTENT_PLAY_LOG,
	CONTENT_TABLE_COLUMNS,
	DB_TABLES,
	DIRECTORY,
	ERROR_CODES,
	ERROR_TABLE,
	GLOBAL_SETTINGS_TABLE,
	HOST_INFO_COLUMNS,
	PLAYLIST_CONTENT_COLUMNS,
	SCHEDULED_JOBS,
	SCREENSHOT_TIMES_BY_ZONE,
	SOCKET_CLIENT_EVENTS,
	TEMPLATE_ZONE_COLUMNS
} from '../constants';
import {
	ApiContent,
	ApiRegisterLicenseResponse,
	ErrorLogs,
	GlobalSettings,
	Host,
	PlayerData,
	License,
	PiInfo,
	PlayerApps,
	PlayerError,
	LicenseInfo,
	ScheduledJob,
	TimeZone,
	ZoneContent
} from '../models';
import { ApiService, CronService, FileService, PlayerService, QueryService, SystemService } from '../services';
import { environment } from '../environment/environment';

// Declarations
const playerRoutes: express.Router = express.Router();
const publicDirectory = path.join(__dirname, '..', '/public');
// eslint-disable-next-line @typescript-eslint/no-var-requires
const sqlstring = require('sqlstring-sqlite');

playerRoutes.post('/player/register', async (req: Request, res: Response) => {
	const _api = new ApiService();
	const body: LicenseInfo = req.body;
	const { register_license } = environment.post;

	// POST - /license/registerv2
	const registerPlayer = await _api.postRequest(register_license, body);

	if (registerPlayer.type === 'error') {
		console.error(error, ERROR_CODES.REGISTER_LICENSE_FAIL);

		res.status(502).json({
			error: {
				message: 'Failed to register license',
				code: ERROR_CODES.REGISTER_LICENSE_FAIL
			}
		});

		return;
	}

	const result = (registerPlayer.response as AxiosResponse<ApiRegisterLicenseResponse>).data;
	res.status(200).send(result);
});

playerRoutes.get('/player/apps', async (req: Request, res: Response) => {
	const _api = new ApiService();
	const { player_app } = environment.get;

	// GET - /playerapp/getapp
	const getPlayerApps = await _api.getRequest(player_app);

	if (getPlayerApps.type === 'error') {
		console.error(error, ERROR_CODES.GET_PLAYER_APPS_FAIL);

		res.status(502).json({
			error: {
				message: 'Failed to retrieve player apps',
				code: ERROR_CODES.GET_PLAYER_APPS_FAIL
			}
		});

		return;
	}

	const result = getPlayerApps.response as AxiosResponse<PlayerApps>;
	res.status(200).send(result.data);
});

playerRoutes.get('/player/data/:licenseKey', async (req: Request, res: Response, next: NextFunction) => {
	const _api = new ApiService();
	const { player_data } = environment.get;
	const { licenseKey } = req.params;
	const endpoint = `${player_data}${licenseKey}`;

	// GET - /pidownloader/getcontents
	const getPlayerData = await _api.getRequest(endpoint);

	if (getPlayerData.type === 'error') {
		console.error(error, ERROR_CODES.PI_DOWNLOADER_FAIL);

		res.status(502).json({
			error: {
				message: 'Failed to retrieve contents from pi downloader',
				code: ERROR_CODES.PI_DOWNLOADER_FAIL
			}
		});

		return;
	}

	const result = getPlayerData.response as AxiosResponse<PlayerData>;
	res.status(200).send(result.data);
});

playerRoutes.get('/player/schedule', async (req: Request, res: Response, next: NextFunction) => {
	const _cron = new CronService();
	const _player = new PlayerService();
	const _socket_client = req.app.get('socket_client');
	const isOffline = req.query.isOffline === 'true';

	try {
		const host_schedule = await _player.get_host_schedule();

		// Set the cronjob schedules if offline mode has been activated
		if (isOffline) {
			console.warn(warning, 'Setting host schedule on offline mode...');
			setScreenshotCronJobs(_cron, _socket_client, host_schedule.timezone, req);
		}

		res.status(200).send(host_schedule);
	} catch (err: any) {
		console.log(error, 'playerRoutes__player_get_schedule', err);
		next(err);
	}
});

playerRoutes.get('/player/fastedge', async (req: Request, res: Response, next: NextFunction) => {
	const _file = new FileService();

	try {
		if (req.query.enabled == '1') {
			console.log(info, 'Fast Edge Enabled');
			await _file.create_config_file({ enable_play_log_sending: true }, DIRECTORY.fast_edge);
		} else {
			console.log(info, 'Fast Edge Disabled');
			await _file.delete_config_file(DIRECTORY.fast_edge);
		}

		res.status(200).send({
			message: `Fast Edge API has been ${req.query.enabled == '1' ? 'Enabled' : 'Disabled'}`
		});
	} catch (err: any) {
		console.log(error, 'playerRoutes__fast_edge_api', err);
		next(err);
	}
});

playerRoutes.get('/player/fastedge/status', async (req: Request, res: Response, next: NextFunction) => {
	const _file = new FileService();

	try {
		const config: any = await _file.read_json(DIRECTORY.fast_edge);
		const config_parsed: any = typeof config === 'string' ? JSON.parse(config) : { enable_play_log_sending: false };

		res.status(200).send(config_parsed);
	} catch (err: any) {
		console.log(error, 'playerRoutes__fast_edge_api', err);
		res.status(200).send({ enable_play_log_sending: false });
	}
});

playerRoutes.get('/player/assets/count', async (req: Request, res: Response, next: NextFunction) => {
	const _file = new FileService();
	const count = await _file.countAssets();
	res.status(200).send({ count });
});

playerRoutes.post('/player/save-data', async (req: Request, res: Response, next: NextFunction) => {
	const _cron = new CronService();
	const _file = new FileService();
	const _query = new QueryService();
	const _system = new SystemService();
	const _socket_client = req.app.get('socket_client');

	try {
		console.log('====== Saving Player Data ======');

		const content: ApiContent[] = req.body.piContents.contents;
		const host_data: Host = req.body.piContents.host;
		const time_zone: TimeZone = req.body.piContents.timezone;
		const template_zone: ZoneContent[] = req.body.piContents.screenZonePlaylistsContents;
		const global_settings: GlobalSettings[] = req.body.globalSettings;

		// Save player data to file for backup
		await fs.writeFile(`${publicDirectory}/player-data.json`, JSON.stringify(req.body));

		// Save Global Settings
		await _query.save_data(
			DB_TABLES.global_settings,
			[
				sqlstring.escape(GLOBAL_SETTINGS_TABLE.vistar_api_key),
				sqlstring.escape(GLOBAL_SETTINGS_TABLE.vistar_net_key)
			],
			[
				sqlstring.escape(global_settings.length > 0 ? global_settings[0].vistarApiKey : null),
				sqlstring.escape(global_settings.length > 0 ? global_settings[0].vistarNetworkId : null)
			]
		);

		// Save Pi Contents to Contents Table
		await saveContentData(content, _query);

		// Save Template, Zone, Content, Data
		await Promise.all(
			template_zone.map(async (t: ZoneContent) => {
				// Saving the Zone Data
				await _query.save_data(
					DB_TABLES.template_zones,
					[
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.template_id),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.x_pos),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.y_pos),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.height),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.width),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.screen_id),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.background),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.playlist_id),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.playlist_type),
						sqlstring.escape(TEMPLATE_ZONE_COLUMNS.zone_order)
					],
					[
						sqlstring.escape(t.screenTemplateZonePlaylist.templateId),
						sqlstring.escape(t.screenTemplateZonePlaylist.xPos),
						sqlstring.escape(t.screenTemplateZonePlaylist.yPos),
						sqlstring.escape(t.screenTemplateZonePlaylist.height),
						sqlstring.escape(t.screenTemplateZonePlaylist.width),
						sqlstring.escape(t.screenTemplateZonePlaylist.screenId),
						sqlstring.escape(t.screenTemplateZonePlaylist.background),
						sqlstring.escape(t.screenTemplateZonePlaylist.playlistId),
						sqlstring.escape(t.screenTemplateZonePlaylist.playlistType),
						sqlstring.escape(t.screenTemplateZonePlaylist.order)
					]
				);

				// Then the Zone Content Data
				let sequence = 1;
				await Promise.all(
					t.contents.map(async (c: ApiContent) => {
						const alternateWeek = c.playlistContentSchedule ? c.playlistContentSchedule.alternateWeek : 0;

						await _query.save_data(
							DB_TABLES.playlist_contents,
							[
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.playlist_id),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.playlist_content_id),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.content_id),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.file_name),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.url),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.file_type),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.handler_id),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.sequence),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.is_fullscreen),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.duration),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.title),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.play_type),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.date_from),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.date_to),
								sqlstring.escape(PLAYLIST_CONTENT_COLUMNS.play_days),
