/**
 * Get the schedules for the screenshot cronjobs
 * @param {string} timeZone
 * @returns
 */
function getScreenshotSchedules(timeZone: null | string) {
	const getRandomNumberInSeconds = () => Math.floor(Math.random() * 59);

	const defaultTime = {
		first_screenshot: { minute: 2, second: getRandomNumberInSeconds() },
		second_screenshot: { minute: 32, second: getRandomNumberInSeconds() }
	};

	if (typeof timeZone === 'undefined' || !timeZone || timeZone.length <= 0) {
		console.warn(warning, 'No timezone found. Setting default screenshot schedules: 2nd and 32nd minute');
		return defaultTime;
	}

	const filtered = SCREENSHOT_TIMES_BY_ZONE.find((t) => t.timezone === timeZone);

	if (typeof filtered === 'undefined') {
		console.warn(warning, 'Could not retrieve screenshot time based on timezone');
		console.log(warning, 'Setting screenshot time(s) to default: 2nd and 32nd minute');
		return defaultTime;
	}

	return {
		first_screenshot: { ...filtered.first_screenshot, second: getRandomNumberInSeconds() },
		second_screenshot: { ...filtered.second_screenshot, second: getRandomNumberInSeconds() }
	};
}

function isEmptyJob(data: ScheduledJob) {
	// Check if data or data.job is undefined or null, or if data.job is an empty object
	return !data || !data.job || (typeof data.job === 'object' && Object.keys(data.job).length === 0);
}

