 */
async function saveHostData(_query: QueryService, data: Host, timeZone: string) {
	console.log(info, 'Saving host info to local database...');

	const columns = Object.values(HOST_INFO_COLUMNS).map((col) => sqlstring.escape(col));
	const values = [
