/**
 * Set the screenshot cron jobs based on timezone
 * @param {CronService} _cron
 * @param _socket
 * @param {string} timeZone
 */
function setScreenshotCronJobs(_cron: CronService, _socket: any, timeZone: null | string, req: Request) {
	console.log(info, 'Setting screenshot cronjobs...');
	let running_cronjobs = req.app.get('running_cronjobs') as ScheduledJob[];

	// Initialize running_cronjobs if it is undefined
	if (!Array.isArray(running_cronjobs)) {
		console.log(warning, 'running_cronjobs is undefined, initializing as an empty array.');
		running_cronjobs = [];
	}

	if (running_cronjobs.length > 0) {
		const currentJobs = running_cronjobs.map((c) => c.slug);
		console.info(info, 'Currently running_cronjobs', currentJobs);
	} else {
		console.warn(warning, 'running_cronjobs is empty :(');
	}

	const exclusions = ['first_screenshot', 'second_screenshot'];
	const { first_screenshot, second_screenshot } = getScreenshotSchedules(timeZone);
	const first_job_index = running_cronjobs.findIndex((job) => job.slug === SCHEDULED_JOBS.first_screenshot);
	const second_job_index = running_cronjobs.findIndex((job) => job.slug === SCHEDULED_JOBS.second_screenshot);

	// if first cronjob EXISTS on the array and if job data is NOT EMPTY
	if (first_job_index !== -1 || !isEmptyJob(running_cronjobs[first_job_index])) {
		running_cronjobs[first_job_index].job.stop();
		console.log(success, 'First screenshot job stopped!');
	}

	// if second cronjob EXISTS on the array and if job data is NOT EMPTY
	if (second_job_index !== -1 || !isEmptyJob(running_cronjobs[second_job_index])) {
		running_cronjobs[second_job_index].job.stop();
		console.log(success, 'Second screenshot job stopped!');
	}

	const new_job_first_screenshot = {
		slug: SCHEDULED_JOBS.first_screenshot,
		job: _cron.scheduled_screenshot(_socket, first_screenshot)
	};
	console.log(
		success,
		`First screenshot schedule set! Minute: ${first_screenshot.minute}, Second: ${first_screenshot.second}`
	);
	const new_job_second_screenshot = {
		slug: SCHEDULED_JOBS.second_screenshot,
		job: _cron.scheduled_screenshot(_socket, second_screenshot)
	};
	console.log(
		success,
		`Second screenshot schedule set: Minute: ${second_screenshot.minute}, Second: ${second_screenshot.second}`
	);

	if (typeof running_cronjobs === 'undefined' || !running_cronjobs || !running_cronjobs.length) {
		console.log(warning, 'Failed to retrieve running cronjobs while setting screenshots');
		console.error(error, 'Could not add scheduled screenshots to running cronjobs list');
		return;
	}

	// Remove old screenshot cronjobs
	running_cronjobs = running_cronjobs.filter((j) => !exclusions.includes(j.slug));

	// Push new first and new second screenshot jobs
	running_cronjobs.push(new_job_first_screenshot);
	running_cronjobs.push(new_job_second_screenshot);

	// Update the list of currently running cronjobs
	req.app.set('running_cronjobs', running_cronjobs);

	const updatedJobs = running_cronjobs.map((c) => c.slug);
	console.log(success, 'Updated running_cronjobs', updatedJobs);
}

/**
 * Sets the timezone
 * @param {SystemService} _system
 * @param {string} timeZone
 * @returns
 */
async function setTimeZoneIfValid(_system: SystemService, timeZone?: string) {
	if (typeof timeZone === 'undefined' || !timeZone || timeZone.length <= 0 || os.platform() !== 'linux') {
		console.log(warning, 'Timezone has not been set!');
		return;
	}

	await _system.setTimezone(timeZone);
	console.log(success, `Timezone has been set to ${timeZone}`);
}

