// Description: Query Service
// Author(s): Earl Vhin Gabuat (earlgabuat@gmail.com)

import { db } from '../db/DatabaseConfiguration';
import { DatabaseError } from '../utils/error';
import { DB_TABLES } from '../constants';
import { HOST_INFO, License, PlayLogDb, QueryServiceOptions } from '../models';
import { info, error, warning, success } from 'log-symbols';
const sqlstring = require('sqlstring-sqlite');
export class QueryService {
	// SQLite Health Status
	db_integrity_check(): Promise<any> {
		return new Promise((resolve, reject) => {
			const sql = 'PRAGMA integrity_check';

			db.all(sql, (err, rows) => {
				if (err) {
					console.log(error, `QueryService__db_integrity_check`);
					reject(new DatabaseError('QueryService__db_integrity_check'));
				} else {
					resolve(rows[0]);
				}
			});
		});
	}

	/**
	 * Database Delete Query
	 * @param table - name of table to be queried
	 */
	delete_all(table: string): Promise<boolean> {
		return new Promise((resolve, reject) => {
			const sql = `DELETE FROM ${table};`;
			db.all(sql, (err) => {
				if (err) {
					console.log(error, `QueryService__delete_all: ${table}`, err);
					reject(new DatabaseError(`QueryService__delete_all: ${table}`));
				} else {
					resolve(true);
				}
			});
		});
	}

	/**
	 * Database Delete Query
	 * @param table - name of table to be queried
	 * @param column - column to Check
	 * @param limit - limit Number
	 */
	delete_where(table: string, column: string, id: string): Promise<boolean> {
		return new Promise((resolve, reject) => {
			const sql = `DELETE FROM ${table} WHERE ${column} = ${id};`;
			db.all(sql, (err) => {
				if (err) {
					console.log(error, `QueryService__delete_where: ${table}`, err);
					reject(new DatabaseError(`QueryService__delete_where: ${table}`));
				} else {
					resolve(true);
				}
			});
		});
	}

	/**
	 * Database Get All Query
	 * @param table - name of table to be queried
	 */
	get_all(table: string): Promise<any[]> {
		return new Promise((resolve, reject) => {
			const sql = `SELECT * FROM ${table}`;
			db.all(sql, (err, rows) => {
				if (err) {
					console.log(error, `QueryService__get_all: ${table}`, err);
					reject(new DatabaseError(`QueryService__get_all: ${table}`));
				}

				resolve(rows);
			});
		});
	}

	/**
	 * Get the first result from selecting all data from the HOSTS table.
	 * Returns false if the table is empty.
	 * @returns {HOST_INFO} | false
	 */
	async get_host_data(): Promise<HOST_INFO | false> {
		try {
			const getHostData = (await this.get_all(DB_TABLES.host_info)) as HOST_INFO[];
			return getHostData.length >= 1 ? getHostData[0] : false;
		} catch (error) {
			return false;
		}
	}

	/**
	 * Database Get By Data Query
	 * @param table - name of table to be queried
	 * @param column - name of column in WHERE
	 * @param data - value for WHERE clause
	 */
	get_by_data(table: string, column: string, data: string | number | boolean): Promise<any[]> {
		return new Promise((resolve, reject) => {
			const sql = `SELECT * FROM ${table} WHERE ${column}=${data}`;
			db.all(sql, (err, rows) => {
				if (err) {
					console.log(error, `QueryService__get_by_data: ${table}`, err);
					reject(new DatabaseError(`QueryService__get_by_data: ${table}`));
				}

				resolve(rows);
			});
		});
	}

	/**
	 * Database Update Query
	 * @param table - name of table to be queried
	 * @param column_value - list of columns to be edited
	 * @param where_column - Table Column,
	 * @param data - Condition Variable
	 */
	update_data(
		table: string,
		column_value: any[],
		where_column: string,
		data: string | number | boolean
	): Promise<boolean> {
		return new Promise((resolve, reject) => {
			const sql = `UPDATE ${table} SET ${column_value} WHERE ${where_column}=${data}`;
			db.all(sql, (err) => {
				if (err) {
					console.log(error, `QueryService__update_data: ${table}, ${err}`);
					reject(new DatabaseError(`QueryService__update_data: ${err}`));
				}

				resolve(true);
			});
		});
	}

	/**
	 * Database Update Query without WHERE Clause
	 * @param table - name of table to be queried
	 * @param column_value - list of columns to be edited
	 * @param data - list of data
	 */
	update_data_no_condition(table: string, column_value_data: any[]): Promise<boolean> {
		return new Promise((resolve, reject) => {
			const sql = `UPDATE ${table} SET ${column_value_data}`;
			db.all(sql, (err) => {
				if (err) {
					console.log(error, `QueryService__update_data: ${table}, ${err}`);
					reject(new DatabaseError(`QueryService__update_data: ${table}`));
				}

				resolve(true);
			});
		});
	}

	/**
	 * Database Insert Query
	 * @param table - name of table to be queried
	 * @param columns - list of columns to be edited
	 * @param data - list of data
	 */
	save_data(table: string, columns: string[], data: Array<string | number | boolean>): Promise<boolean> {
		return new Promise((resolve, reject) => {
			const sql = `INSERT INTO ${table} (${columns}) VALUES (${data})`;
			db.all(sql, (err) => {
				if (err) {
					console.log(
						error,
						`QueryService__save_data: ${table}, 
                        ${sql}, 
                        ${err}`
					);
					reject(new DatabaseError(`QueryService__save_data: ${table}`));
				}

				resolve(true);
			});
		});
	}

	async clearTables(names: string[]) {
		try {
			const tablesToClear: Promise<boolean>[] = names.map((name) => {
				return this.delete_all(name);
			});

			await Promise.all(tablesToClear);
			return true;
		} catch (err) {
			console.error('Failed to clear table(s)', err);
			return false;
		}
	}

	async clearPlayLogTable() {
		console.info(info, 'Clearing play logs table...');
		return await this.clearTables([DB_TABLES.content_play_log]);
	}

	/**
	 * Get the license record from the database
	 * @returns Returns false if no records are found
	 */
	async getLicenseData(): Promise<false | License> {
		const result = await this.getDataFromTable(DB_TABLES.license, { returnAsArray: true });

		if (!result) return result;

		return result[0] as License;
	}

	async getPlayLogs(): Promise<false | PlayLogDb[]> {
		const result = await this.getDataFromTable(DB_TABLES.content_play_log, { returnAsArray: true });

		if (!result) return result;

		return result as PlayLogDb[];
	}

	async getDataFromTable(tableName: string, options?: QueryServiceOptions) {
		console.log(info, `Retrieving ${tableName} data from the database...`);

		try {
			const result = (await this.get_all(tableName)) as any[];

			if (!result.length) {
				console.warn(warning, `No ${tableName} data found on the database!`);
				return false;
			}

			if (options?.logAsConsoleTable) this.logAsConsoleTable(tableName, result);
			else console.log(success, `Found ${tableName} data on the database!`, result);

			if (options?.returnAsArray) return result;
			else return result[0];
		} catch (e) {
			console.error(error, 'QueryService__get_data_from_table: ', e);
			return false;
		}
	}

	private logAsConsoleTable(tableName: string, data: any[]) {
		let log = [];

		switch (tableName) {
			case DB_TABLES.license:
				log.push(data[0] as License);
				break;
			default:
				console.log('Just passing by...');
		}

		console.table(log);
	}
}

