// Description: Updates Route
// Author(s): Earl Vhin Gabuat (earlgabuat@gmail.com)

import * as child from 'child_process';
import express, { NextFunction, Request, Response } from 'express';
import * as logsym from 'log-symbols';
import * as path from 'path';

import { APP_TABLE, DB_TABLES, UPDATE_LOGS_TABLE } from '../constants/DatabaseTables';
import { DIRECTORY } from '../constants/Directories';
import { APP_REPO, PLAYER_APP } from '../constants/PlayerApps';
import { SOCKET_EVENTS } from '../constants/SocketEvents';
import { ApiAppVersion } from '../models/ApiVersionModel';
import { PlayerApp, ToUpdate, UpdateLog } from '../models/LocalVersionModel';
import { FileService } from '../services/FileService';
import { QueryService } from '../services/QueryService';
import { UpdateService } from '../services/UpdateService';

// Declarations
const updateRoutes: express.Router = express.Router();
// eslint-disable-next-line @typescript-eslint/no-var-requires
const sqlstring = require('sqlstring-sqlite');

// Get Updates
updateRoutes.get('/update', async (req: Request, res: Response, next: NextFunction) => {
	console.log('====== Software Update Started ======');
	try {
		// Required
		const _socket = req.app.get('io');
		const _update: UpdateService = new UpdateService();
		const _query: QueryService = new QueryService();
		const update_availability: PlayerApp[] = await _query.get_by_data(DB_TABLES.apps, APP_TABLE.update_available, sqlstring.escape(1));

		// Should download updates that is available
		const dl_updates: ToUpdate[] = await _update.download_updates(update_availability, _socket);
		console.log(logsym.success, 'To be Updated', dl_updates);

		for (const update of dl_updates) {
			let directory: string | null;
			let repo: string | null;

			switch (update.app_name) {
				case PLAYER_APP.server:
					directory = DIRECTORY.update_folder_server;
					repo = APP_REPO.server;
					break;

				case PLAYER_APP.ui:
					directory = DIRECTORY.update_folder_ui;
					repo = APP_REPO.ui;
					break;

				case PLAYER_APP.chrome:
					directory = DIRECTORY.update_folder_chromium;
					repo = APP_REPO.puppeteer;
					break;

				case PLAYER_APP.electron:
					directory = DIRECTORY.update_folder_electron;
					repo = APP_REPO.electron;
					break;

				default:
					directory = null;
					repo = null;
					break;
			}

			if (!directory || !repo) {
				console.warn(logsym.warning, 'Directory and/or repo are unrecognized. Skipping this:', update);
				continue;
			}

			const updateResult = await _update.unzip_downloaded_updates(directory, repo);
			console.log(logsym.success, 'Updates downloaded successfully!', updateResult);
			_socket.emit(SOCKET_EVENTS.unzipped, update.app_version);
		}

		res.status(200).send({ message: 'Updates Ready to be Applied' });
	} catch (e) {
		console.error(logsym.error, 'Unable to download updates', e);
		next(e);
	}
});

updateRoutes.post('/update/apps', async (req: Request, res: Response) => {
	console.log('====== Saving Apps ======');
	const _query: QueryService = new QueryService();
	const _file: FileService = new FileService();

	try {
		// Clear Apps Table
		await _query.delete_all(DB_TABLES.apps);
		console.log(logsym.success, 'App Table Cleared');

		// Get Apps Version via Package.JSON
		const electron: any = await _file.read_json(`${DIRECTORY.player_electron}/package.json`);

		console.log(logsym.info, 'electron', electron.error ? 'N/A' : JSON.parse(electron).version);

		const server: any = await _file.read_json(`${DIRECTORY.player_server}/package.json`);

		console.log(logsym.info, 'server', server.error ? 'N/A' : JSON.parse(server).version);

		const ui: any = await _file.read_json(`${DIRECTORY.player_ui}/package.json`);

		console.log(logsym.info, 'ui', ui.error ? 'N/A' : JSON.parse(ui).version);

		const chromium: any = await _file.read_json(`${DIRECTORY.player_puppeteer}/package.json`);

		console.log(logsym.info, 'puppeteer', chromium.error ? 'N/A' : JSON.parse(chromium).version);

		// POST Data from Player UI
		const apps: ApiAppVersion[] = req.body;

		// Save Apps
		if (apps.length > 0) {
			const appsLog = apps.map((app) => {
				return {
					Id: app.appId,
					Name: app.appName,
					Version: app.currentVersion,
					'Date Created': app.dateCreated
				};
			});

			console.log('====== Apps List ======');
			console.table(appsLog);

			await Promise.all(
				apps.map(async (i: ApiAppVersion) => {
					// Setting Versions of current App Index
					const app_version = (() => {
						if (i.appName === PLAYER_APP.electron) {
							return electron.error ? null : JSON.parse(electron).version;
						} else if (i.appName === PLAYER_APP.server) {
							return server.error ? null : JSON.parse(server).version;
						} else if (i.appName === PLAYER_APP.ui) {
							return ui.error ? null : JSON.parse(ui).version;
						} else if (i.appName === PLAYER_APP.chrome) {
							return chromium.error ? null : JSON.parse(chromium).version;
						}
					})();

					await _query.save_data(
						DB_TABLES.apps,
						[APP_TABLE.id, APP_TABLE.app, APP_TABLE.github_url, APP_TABLE.current_version, APP_TABLE.update_available],
						[sqlstring.escape(i.appId), sqlstring.escape(i.appName), sqlstring.escape(i.githubUrl), sqlstring.escape(app_version), 0]
					);
				})
			);
		}

		console.log(logsym.success, 'Apps Saved Succesfully');
		res.status(200).send({ message: 'Apps Saved Succesfully' });
	} catch (err: any) {
		console.log(logsym.error, 'updateRoutes_update_apps', err);
		res.status(200).send({ error: true, message: 'App Files Not Found' });
	}
});

// Apply Updates Route
updateRoutes.get('/update/apply', async (req: Request, res: Response, next: NextFunction) => {
	console.log('====== Applying Updates ======');
	try {
		console.log(logsym.info, 'Applying Updates, Running Update Script');
		await child.exec(`lxterminal --command=${path.join(__dirname, '..', '/bin/apply-updates.sh')} &`);
		res.status(200).send({ message: 'Restarting' });
	} catch (err: any) {
		console.log(logsym.error, 'updateRoutes__update_apply', err);
		next(err);
	}
});

updateRoutes.post('/update/logs', async (req: Request, res: Response, next: NextFunction) => {
	const _query: QueryService = new QueryService();
	try {
		// POST Data from Player UI
		const log: UpdateLog = req.body;

		// Delete Table Data
		await _query.delete_all(DB_TABLES.update_logs);

		// Add Query Status
		await _query.save_data(
			DB_TABLES.update_logs,
			[UPDATE_LOGS_TABLE.status, UPDATE_LOGS_TABLE.desc, UPDATE_LOGS_TABLE.date],
			[sqlstring.escape(log.status), sqlstring.escape(log.desc), sqlstring.escape(log.date)]
		);

		res.status(200).send({ message: 'Update Logs Saved' });
	} catch (err: any) {
		console.log(logsym.error, 'updateRoutes__update_logs', err);
		next(err);
	}
});

