// Description: File Service
// Author(s): Earl Vhin Gabuat (earlgabuat@gmail.com)

import { Server as SocketServer } from 'socket.io';
import { APP_REPO, DIRECTORY, FILETYPES, SOCKET_EVENTS } from '../constants';
import { Assets } from '../models';
import { DownloadError } from '../utils/error';
import { SystemService } from './SystemService';
import { error, info, success, warning } from 'log-symbols';
import * as fs from 'fs-extra';
import scrape from 'website-scraper';
import request from 'request';

export class DownloadService {
	asset_count: number;
	directory: any;
	isMediaAsset: string[] = ['image_asset', 'video_asset'];

	constructor(private _io: SocketServer, private _assets_server: any) {
		this.asset_count = 0;
		this.directory =
			this._assets_server == APP_REPO.server ? DIRECTORY.assets_folder_node : DIRECTORY.assets_folder;
		this.folder_checkup(this.directory);
	}

	/**
	 * Downloads assets asynchronously.
	 *
	 * @param {Assets[]} data An array of assets to be downloaded.
	 * @returns {Promise<boolean>} Resolves with true if all assets are downloaded successfully, otherwise rejects with a DownloadError.
	 */
	async downloadAssets(data: Assets[]): Promise<boolean> {
		try {
			const downloadPromises = data.map(async (asset) => {
				try {
					// Determine file type and classification
					const isFeed = asset.file_type === FILETYPES.feed || asset.file_type === FILETYPES.weather;
					const isMediaAsset = this.isMediaAsset.includes(asset.classification);

					// Setup download for feed or asset
					const download = isFeed && !isMediaAsset ? this.download_feed(asset) : this.download_file(asset);

					// Run download
					await download;
				} catch (downloadErr) {
					console.error(`Error downloading asset: ${asset.file_name}`, downloadErr);
				}
			});

			await Promise.all(downloadPromises);
			return true;
		} catch (err) {
			console.error('Error encountered while downloading assets', err);
			throw new DownloadError('DownloadService__downloadAssets');
		}
	}

	/**
	 * Scrape feed file type assets
	 * @param f file to be downloaded
	 */
	download_feed(f: Assets) {
		return new Promise((resolve, reject) => {
			// Scrape Options
			const options = {
				directory: `${this.directory}/${f.content_id}`,
				urls: [f.url]
			};

			if (f.classification === 'live_stream') {
				this.asset_count += 1;

				console.log(success, this.asset_count, f.title);

				this._io.emit(SOCKET_EVENTS.file_downloaded, {
					progress: 100,
					content_id: f.content_id
				});

				this._io.emit(SOCKET_EVENTS.downloaded, {
					count: this.asset_count,
					filename: f.title
				});

				resolve(this.asset_count);
				return;
			}

			// Delete incoming feed if already present in assets folder
			if (f.classification !== 'filler') {
				fs.remove(`${this.directory}/${f.content_id}`, async (err) => {
					try {
						if (err) {
							console.log(error, 'DownloadService__download_file#fs.remove', err);
							reject(new DownloadError('DownloadService__download_file#fs.remove'));
						} else {
							// Download Feed
							await scrape(options);

							this.asset_count += 1;

							console.log(success, this.asset_count, f.title);

							this._io.emit(SOCKET_EVENTS.file_downloaded, {
								progress: 100,
								content_id: f.content_id
							});

							this._io.emit(SOCKET_EVENTS.downloaded, {
								count: this.asset_count,
								filename: f.title
							});

							resolve(this.asset_count);
						}
					} catch (err: any) {
						console.log(warning, 'DownloadService__download_feed_!filler', err);

						reject(new DownloadError('DownloadService__download_feed_!filler'));
					}
				});
			} else {
				fs.access(options.directory, async (err) => {
					try {
						if (err) {
							// Means feed does not exist, Download Feed
							await scrape(options);
							this.asset_count += 1;

							console.log(success, this.asset_count, f.title);

							this._io.emit(SOCKET_EVENTS.file_downloaded, {
								progress: 100,
								content_id: f.content_id
							});

							this._io.emit(SOCKET_EVENTS.downloaded, {
								count: this.asset_count,
								filename: f.title
							});

							resolve(this.asset_count);
						} else {
							this.asset_count += 1;

							console.log(this.asset_count);

							console.log(info, `${this.asset_count} ${f.title} already exists and is a filler`);

							this._io.emit(SOCKET_EVENTS.file_downloaded, {
								progress: 100,
								content_id: f.content_id
							});

							this._io.emit(SOCKET_EVENTS.downloaded, {
								count: this.asset_count,
								filename: f.title
							});

							resolve(this.asset_count);
						}
					} catch (err: any) {
						console.log(warning, 'DownloadService__download_feed_filler', err);

						reject(new DownloadError('DownloadService__download_feed_filler'));
					}
				});
			}
		});
	}

	/**
	 * Download Videos, Images
	 * @param f file to be downloaded
	 */
	download_file(f: Assets) {
		return new Promise((resolve, reject) => {
			const isMediaAsset = this.isMediaAsset.includes(f.classification);
			const filename = !isMediaAsset ? f.file_name : this.extractFilenameFromUrl(f.url);

			fs.access(`${this.directory}/${filename}`, async (err) => {
				if (err) {
					let file_size = 0;
					let file_size_downloaded = 0;

					const req = request({
						method: 'GET',
						uri: f.url
					});

					const out = fs.createWriteStream(`${this.directory}/${filename}`);

					req.pipe(out);

					req.on('response', function (data) {
						file_size = parseInt(data.headers['content-length']!);
					});

					req.on('data', (chunk) => {
						file_size_downloaded = file_size_downloaded + chunk.length;

						this._io.emit(SOCKET_EVENTS.file_downloaded, {
							progress: ((file_size_downloaded / file_size) * 100).toFixed(2),
							content_id: f.content_id
						});
					});

					req.on('complete', async () => {
						this.asset_count += 1;

						console.log(success, this.asset_count, filename);

						const saved_file_size = await fs.stat(`${this.directory}/${filename}`);

						if (saved_file_size.size > 0) {
							this._io.emit(SOCKET_EVENTS.downloaded, {
								count: this.asset_count,
								filename: f.title
							});

							resolve(this.asset_count);
						} else {
							await fs.unlink(`${this.directory}/${filename}`);
							await this.download_file(f);
						}
					});

					req.on('error', (error) => {
						reject(error);
					});
				} else {
					const saved_file_size = await fs.stat(`${this.directory}/${filename}`);

					if (saved_file_size.size > 0) {
						this.asset_count += 1;

						console.log(info, `${this.asset_count} ${filename} already exists`);

						this._io.emit(SOCKET_EVENTS.file_downloaded, {
							progress: 100,
							content_id: f.content_id
						});

						this._io.emit(SOCKET_EVENTS.downloaded, {
							count: this.asset_count,
							filename: f.title
						});

						resolve(this.asset_count);
					} else {
						await fs.unlink(`${this.directory}/${filename}`);
						await this.download_file(f);
					}
				}
			});
		});
	}

	/**
	 * Check if Assets Folder exists, If not create it.
	 * @param data - Directory to check
	 */
	folder_checkup(data: any): void {
		fs.ensureDir(this.directory, () => {
			console.log(success, 'Assets Folder Exists');
			this.directory = data;
		});
	}

	/**
	 * Sets assets folder ownership
	 * @returns {Promise<boolean>}
	 */
	async set_assets_folder_ownership(): Promise<boolean> {
		const _system = new SystemService();
		return await _system.setFolderOwnership(this.directory);
	}

	/**
	 * Extracts filename from the URL from image/video feed
	 * @param url
	 * @returns {string}
	 */
	private extractFilenameFromUrl(url: string): string {
		const pathname = new URL(url).pathname;
		const segments = pathname.split('/');
		const lastSegment = segments.pop() || '';
		return lastSegment.split(/[?#]/)[0];
	}
}

