// sshConfig.js - Environment-specific SSH configurations

const environments = {
	// Development environment
	dev: {
		host: '192.168.1.10',
		port: 22,
		username: 'pi',
		password: 'raspberry',
		remotePath: '/home/pi/n-compasstv/player-server/'
	},

	// Staging environment
	staging: {
		host: '192.168.0.10',
		port: 22,
		username: 'pi',
		password: 'raspberry',
		remotePath: '/home/pi/n-compasstv/player-server/'
	},

	// Production environment
	prod: {
		host: '192.168.0.10',
		port: 22,
		username: 'pi',
		password: 'raspberry',
		remotePath: '/home/pi/n-compasstv/player-server/'
	},

	// Local testing environment
	local: {
		host: '192.168.0.10',
		port: 22,
		username: 'pi',
		password: 'raspberry',
		remotePath: '/home/pi/n-compasstv/player-server/'
	},

	// Sandbox environment
	sandbox: {
		host: '192.168.0.10',
		port: 22,
		username: 'pi',
		password: 'raspberry',
		remotePath: '/home/pi/n-compasstv/player-server/'
	},

	// Jenkins/CI environment
	jenkins: {
		host: '192.168.0.10',
		port: 22,
		username: 'pi',
		password: 'raspberry',
		remotePath: '/home/pi/n-compasstv/player-server/'
	}
};

// Get environment from NODE_ENV or default to 'dev'
const getEnvironment = () => {
	const env = process.env.NODE_ENV || 'dev';

	// Map production to prod for consistency
	if (env === 'production') {
		return 'prod';
	}

	// Return the environment if it exists, otherwise default to dev
	return environments[env] ? env : 'dev';
};

// Export the configuration for the current environment
module.exports = environments[getEnvironment()];

const { src, dest, series } = require('gulp');
const minify = require('gulp-uglify');
const sftp = require('gulp-sftp-up4');
const GulpSSH = require('gulp-ssh');
const sshConfig = require('./sshConfig'); // Require SSH configuration
const fs = require('fs');

// Files to bundle
const files = ['./package.json', './.env', './src/bin/*.*', './nct-vistar-1.0.1.tgz'];

// Task to bundle JavaScript files
const bundleJS = () => {
	return src(['./dist/**/*.js', '!./dist/**/*.spec.js']).pipe(minify()).pipe(dest('./bundle'));
};

// Task to copy required files
const copyFiles = () => {
	return src(files, { base: './', dot: true }).pipe(dest('./bundle'));
};

// Task to modify package.json and remove devDependencies
const modifyPackageJson = (cb) => {
	fs.readFile('package.json', 'utf8', (err, data) => {
		if (err) {
			return cb(err);
		}

		const json = JSON.parse(data);
		delete json.devDependencies;

		fs.writeFile('./bundle/package.json', JSON.stringify(json, null, 2), 'utf8', cb);
	});
};

// Task to modify .env file and set correct NODE_ENV
const modifyEnvFile = (cb) => {
	fs.readFile('.env', 'utf8', (err, data) => {
		if (err) {
			return cb(err);
		}

		// Get the current NODE_ENV from process.env, default to 'prod'
		const currentNodeEnv = process.env.NODE_ENV || 'prod';

		// Replace the NODE_ENV line in .env file
		const updatedEnvContent = data.replace(/^NODE_ENV=.*$/m, `NODE_ENV=${currentNodeEnv}`);

		fs.writeFile('./bundle/.env', updatedEnvContent, 'utf8', cb);
	});
};

// Task to verify .env file has correct NODE_ENV before compression
const verifyEnvFile = (cb) => {
	fs.readFile('./bundle/.env', 'utf8', (err, data) => {
		if (err) {
			console.error('Error reading bundle/.env file:', err.message);
			return cb(err);
		}

		// Get expected NODE_ENV from process.env
		const expectedNodeEnv = process.env.NODE_ENV || 'prod';

		// Extract NODE_ENV from .env file
		const nodeEnvMatch = data.match(/^NODE_ENV=(.*)$/m);
		if (!nodeEnvMatch) {
			console.error('NODE_ENV not found in bundle/.env file');
			return cb(new Error('NODE_ENV not found in .env file'));
		}

		const actualNodeEnv = nodeEnvMatch[1].trim();

		if (actualNodeEnv !== expectedNodeEnv) {
			console.error(`NODE_ENV mismatch in bundle/.env:`);
			console.error(`   Expected: ${expectedNodeEnv}`);
			console.error(`   Actual:   ${actualNodeEnv}`);
			return cb(new Error(`NODE_ENV mismatch: expected ${expectedNodeEnv}, got ${actualNodeEnv}`));
		}

		console.log(`Verified bundle/.env has correct NODE_ENV=${actualNodeEnv}`);
		cb();
	});
};

// Task to upload bundle folder contents via SFTP
const uploadToSFTP = () => {
	console.log(`Uploading to ${process.env.NODE_ENV || 'dev'} environment:`, sshConfig.host);
	return src('./bundle/**', { dot: true })
		.pipe(
			sftp({
				host: sshConfig.host,
				port: sshConfig.port,
				user: sshConfig.username,
				pass: sshConfig.password,
				remotePath: sshConfig.remotePath,
				// SFTP options for reliability
				timeout: 30000, // 30 second timeout
				retries: 2, // Retry failed uploads
				retryDelay: 2000, // 2 second delay between retries
				// Auto-accept host keys for non-production environments
				autoConfirm: process.env.NODE_ENV !== 'prod'
			})
		)
		.on('error', (err) => {
			console.error('SFTP Upload Error:', err.message);
			if (err.message.includes('ECONNREFUSED')) {
				console.error('SSH Connection refused. Please check:');
				console.error('  - Target host is reachable:', sshConfig.host);
				console.error('  - SSH service is running on port:', sshConfig.port);
				console.error('  - Network connectivity to target environment');
			} else if (err.message.includes('Authentication')) {
				console.error('SSH Authentication failed. Please check:');
				console.error('  - Username and password are correct');
				console.error('  - SSH password authentication is enabled');
			} else if (err.message.includes('Host key')) {
				console.error('SSH Host key verification failed.');
				console.error('For first-time connections, you may need to manually connect once:');
				console.error(`  ssh pi@${sshConfig.host}`);
			}
		})
		.on('end', () => {
			console.log('Uploaded files via SFTP (including hidden files)');
		});
};

// SSH configuration with fallback handling for first-time connections
const sshOptions = {
	...sshConfig,
	// Add SSH options for first-time connections
	readyTimeout: 30000, // 30 second timeout
	algorithms: {
		cipher: ['aes128-ctr', 'aes192-ctr', 'aes256-ctr'],
		hmac: ['hmac-sha2-256', 'hmac-sha2-512', 'hmac-sha1'],
		compress: ['none']
	},
	// Auto-accept host keys for first-time connections (dev environments only)
	hostHash: 'sha256',
	hostVerifier: process.env.NODE_ENV !== 'prod' ? () => true : undefined
};

// Task to set file permissions
const ssh = new GulpSSH({
	ignoreErrors: false,
	sshConfig: sshOptions
});

const showDeploymentBanner = () => {
	const packageJson = JSON.parse(fs.readFileSync('./package.json', 'utf8'));
	const version = packageJson.version;
	const environment = process.env.NODE_ENV || 'dev';

	return ssh.exec(
		[
			// Create the banner script content
			`cat > /tmp/deployment_banner.sh << 'EOF'
#!/bin/bash
echo ""
echo ""
echo "╔═══════════════════════════════════════════════════════════╗"
echo "║                     NTV360 DEPLOYMENT                     ║"
echo "╠═══════════════════════════════════════════════════════════╣"
echo "║  ███╗   ██╗████████╗██╗   ██╗██████╗  ██████╗  ██████╗    ║"
echo "║  ████╗  ██║╚══██╔══╝██║   ██║╚════██╗██╔════╝ ██╔═████╗   ║"
echo "║  ██╔██╗ ██║   ██║   ██║   ██║ █████╔╝███████╗ ██║██╔██║   ║"
echo "║  ██║╚██╗██║   ██║   ╚██╗ ██╔╝ ╚═══██╗██╔═══██╗████╔╝██║   ║"
echo "║  ██║ ╚████║   ██║    ╚████╔╝ ██████╔╝╚██████╔╝╚██████╔╝   ║"
echo "║  ╚═╝  ╚═══╝   ╚═╝     ╚═══╝  ╚═════╝  ╚═════╝  ╚═════╝    ║"
echo "╠═══════════════════════════════════════════════════════════╣"
echo "║  Starting Player Server Deployment!                       ║"
echo "║  Environment: ${environment.toUpperCase()}                                         ║"
echo "║  Deployment Time: $(date '+%Y-%m-%d %H:%M:%S')                     ║"
echo "║  Version: ${version}                                          ║"
echo "╚═══════════════════════════════════════════════════════════╝"
echo ""
echo "Uploading files to remote server..."
sleep 3
echo "Setting file permissions..."
sleep 3
echo "Restarting services..."
sleep 8
echo "Deployment completed successfully!"
echo "Terminal will close in 5 seconds..."
sleep 5
EOF`,
			// Make the script executable
			`chmod +x /tmp/deployment_banner.sh`,
			// Launch gnome-terminal with the banner script
			`gnome-terminal --display=:0 --geometry=80x25 --title="NTV360 Deployment" -- /tmp/deployment_banner.sh &`,
			'sleep 2'
		],
		{
			filePath: 'deployment.log'
		}
	);
};

// Task to test SSH connectivity (useful for first-time setup)
const testSSHConnection = () => {
	console.log(`Testing SSH connection to ${process.env.NODE_ENV || 'dev'} environment:`, sshConfig.host);
	return ssh
		.exec(['echo "SSH connection successful!"', 'whoami', 'pwd', 'uname -a'], { filePath: 'ssh-test.log' })
		.on('error', (err) => {
			console.error('SSH Connection Test Failed:', err.message);
			console.error('This might be a first-time connection. Try these steps:');
			console.error(`1. Manual SSH connection: ssh pi@${sshConfig.host}`);
			console.error('2. Accept the host key fingerprint when prompted');
			console.error('3. Verify credentials work manually');
			console.error('4. Then retry the deployment command');
		})
		.on('end', () => {
			console.log('SSH connectivity test completed successfully');
		});
};

const stopPlayer = () => {
	return ssh.exec(['pm2 stop all'], { filePath: 'commands.log' }).on('end', () => {
		console.log('Player Stopped');
	});
};

const setFilePermissions = () => {
	// Read version from package.json for deployment summary
	const packageJson = JSON.parse(fs.readFileSync('./package.json', 'utf8'));
	const version = packageJson.version;

	return ssh
		.exec(
			[
				// Set executable permissions on shell scripts
				`chmod 755 ${sshConfig.remotePath}src/bin/*.sh`,
				`echo "Shell scripts permissions set"`,
				// Set executable permissions on main app entry point
				`chmod 755 ${sshConfig.remotePath}src/app.js`,
				`echo "Main application permissions set"`,
				// Set read permissions on config files
				`chmod 644 ${sshConfig.remotePath}package.json`,
				`chmod 644 ${sshConfig.remotePath}.env`,
				`echo "Configuration files permissions set"`,
				// Set read permissions on all other JS files
				`find ${sshConfig.remotePath}src -name "*.js" -not -path "*/bin/*" -not -name "app.js" -exec chmod 644 {} +`,
				`echo "JavaScript files permissions set"`,
				`echo ""`,
				`echo "Restarting Player Server..."`,
				'sleep 1',
				// Restart the player server
				'pm2 restart player-server',
				`echo ""`,
				`echo "DEPLOYMENT COMPLETED SUCCESSFULLY!"`,
				`echo ""`,
				`echo "╔═══════════════════════════════════════════════════════════╗"`,
				`echo "║                 DEPLOYMENT SUMMARY                        ║"`,
				`echo "╠═══════════════════════════════════════════════════════════╣"`,
				`echo "║  Version: ${version}                                          ║"`,
				`echo "║  Files deployed and permissions set                       ║"`,
				`echo "║  Player Server restarted successfully                     ║"`,
				`echo "║  Server is ready to serve content                         ║"`,
				`echo "╚═══════════════════════════════════════════════════════════╝"`,
				`echo ""`,
				'sleep 3'
			],
			{
				filePath: 'deployment.log'
			}
		)
		.on('end', () => {
			console.log('Deployment completed with visual feedback on target host');
		});
};

// Create the complete deployment flow
const deploymentFlow = (cb) => {
	return series(exports.bundle, showDeploymentBanner, uploadToSFTP, setFilePermissions)(cb);
};

// Define series of tasks
exports.bundle = series(bundleJS, copyFiles, modifyPackageJson, modifyEnvFile, verifyEnvFile);
exports.upload = uploadToSFTP;
exports.uploadWithBanner = deploymentFlow;
exports.stopPlayer = stopPlayer;
exports.setPermissions = setFilePermissions;
exports.showBanner = showDeploymentBanner;
exports.testSSH = testSSHConnection;

